INSERT INTO `wp_options` VALUES ('162','facetwp_updater_response','{\"facetwp\":{\"name\":\"FacetWP\",\"slug\":\"facetwp\",\"version\":\"4.5\",\"requires\":\"5.0\",\"tested\":\"6.9.4\",\"last_updated\":\"2026-03-23\",\"sections\":{\"description\":\"\",\"changelog\":\"<h4>4.5<\\/h4>\\r\\n<ul>\\r\\n<li>March 23, 2026<\\/li>\\r\\n<li>New: see the <a href=\\\"https:\\/\\/facetwp.com\\/whats-new-in-facetwp-4-5\\/\\\" target=\\\"_blank\\\">FacetWP 4.5 release post<\\/a><\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.4.1<\\/h4>\\r\\n<ul>\\r\\n<li>April 23, 2025<\\/li>\\r\\n<li>New: see the <a href=\\\"https:\\/\\/facetwp.com\\/whats-new-in-facetwp-4-4\\/\\\" target=\\\"_blank\\\">FacetWP 4.4 release post<\\/a><\\/li>\\r\\n<li>Fix: 4.4.1 fixed a gmaps_api_key upgrade error for some sites<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3.6<\\/h4>\\r\\n<ul>\\r\\n<li>January 31, 2025<\\/li>\\r\\n<li>Fix: escape the gmaps API key field (props Tom B)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3.5<\\/h4>\\r\\n<ul>\\r\\n<li>December 16, 2024<\\/li>\\r\\n<li>Fix: various bugfixes and tweaks<\\/li>\\r\\n<li>Fix: better support ACF fields in the \\\"Other data source\\\" setting<\\/li>\\r\\n<li>Improved: revamped the \\\"UI type\\\" component (used for various add-ons)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3.4<\\/h4>\\r\\n<ul>\\r\\n<li>November 21, 2024<\\/li>\\r\\n<li>Improved: lots of admin UI tweaks<\\/li>\\r\\n<li>Improved: improved import\\/export UI to allow \\\"select all\\\"<\\/li>\\r\\n<li>Improved: support WooCommerce stock status for ACF fields<\\/li>\\r\\n<li>Fix: CodeMirror (code editor) initialization bug<\\/li>\\r\\n<li>Fix: the temp table should get deleted when the index is purged<\\/li>\\r\\n<li>Fix: only modify term_link URLs after the `woocommerce_shop_loop_header` action fires<\\/li>\\r\\n<li>New: added `total_unfiltered` property to the pager arguments (get unfiltered count)<\\/li>\\r\\n<li>New: `Enable automatic indexing` setting for those wanting to re-index manually<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3.3<\\/h4>\\r\\n<ul>\\r\\n<li>August 20, 2024<\\/li>\\r\\n<li>Fix: not all \\\"product\\\" post types belong to WooCommerce<\\/li>\\r\\n<li>Fix: renamed the `facetwp_transients` wp_option to prevent 3rd party conflicts<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3.2<\\/h4>\\r\\n<ul>\\r\\n<li>August 19, 2024<\\/li>\\r\\n<li>New: visual code editor (for listing templates)!<\\/li>\\r\\n<li>Improved: better update-check logic<\\/li>\\r\\n<li>Improved: ability to translate listing builder button labels<\\/li>\\r\\n<li>Improved: fSelect - support for 3+ nesting levels<\\/li>\\r\\n<li>Improved: added `facetwp_admin_settings_capability` hook to allow trusted editors to access FacetWP settings<\\/li>\\r\\n<li>Improved: better ACF handling for out-of-stock WooCommerce products<\\/li>\\r\\n<li>Improved: added admin warning icon when Debug Mode is enabled<\\/li>\\r\\n<li>Fix: ACF nested repeater field indexing<\\/li>\\r\\n<li>Fix: indexing progress bar not updating correctly when the auto-indexer is disabled<\\/li>\\r\\n<li>Fix: set a global default facet orderby (count)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3.1<\\/h4>\\r\\n<ul>\\r\\n<li>June 20, 2024<\\/li>\\r\\n<li>Improved: styling for \\\"locked\\\" (i.e. code-based) facets and templates<\\/li>\\r\\n<li>Improved: Listing builder - hide the \\\"Reset\\\" facet mobile header<\\/li>\\r\\n<li>Improved: checkboxes - the \\\"See more\\/less\\\" links are translatable<\\/li>\\r\\n<li>Fix: query detection should ignore queries running inside `get_the_excerpt` (i.e. some block-based templates)<\\/li>\\r\\n<li>Fix: ACF - prevent deprecated notices for NULL date values<\\/li>\\r\\n<li>Fix: `FWP.active_facet` not working in some browsers<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.3<\\/h4>\\r\\n<ul>\\r\\n<li>May 7, 2024<\\/li>\\r\\n<li>New: search facets - added \\\"Enable relevance\\\" UI setting<\\/li>\\r\\n<li>Improved: slider facets - only trigger a refresh when the slider handles actually move<\\/li>\\r\\n<li>Improved: debug mode - show all FacetWP-related hooks in use (even ones that return a boolean)<\\/li>\\r\\n<li>Improved: proximity facets - allow radius unit to be translatable<\\/li>\\r\\n<li>Improved: WooCommerce - better counts calculation for the `facetwp_woocommerce_support_categories_display` hook (WC category filtering)<\\/li>\\r\\n<li>Updated dependencies<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.12<\\/h4>\\r\\n<ul>\\r\\n<li>March 12, 2024<\\/li>\\r\\n<li>New: pager facet - added \\\"Scroll target\\\" and \\\"Scroll offset\\\" UI settings to fine-tune pager scrolling<\\/li>\\r\\n<li>Improved: Date range - hide date range when no dates are available<\\/li>\\r\\n<li>Improved: Date range - add placeholder for disabled dates<\\/li>\\r\\n<li>Improved: better Multi-site debugging<\\/li>\\r\\n<li>Improved: misc styling tweaks and Slider facet styling for RTL support<\\/li>\\r\\n<li>Improved: better ACF checks to ensure that fields still exist<\\/li>\\r\\n<li>Fix: change date defaults from 0 to empty string<\\/li>\\r\\n<li>Fix: ensure that Pager facet\'s scroll offset is an integer<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.11<\\/h4>\\r\\n<ul>\\r\\n<li>January 22, 2024<\\/li>\\r\\n<li>Fix: another Date Range typo (last one!)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.10<\\/h4>\\r\\n<ul>\\r\\n<li>January 18, 2024<\\/li>\\r\\n<li>Fix: typo causing Date Range facets to break<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.9<\\/h4>\\r\\n<ul>\\r\\n<li>January 17, 2024<\\/li>\\r\\n<li>Improved: Google maps - added sessionTokens to (hopefully) reduce the number of API calls<\\/li>\\r\\n<li>Improved: added \\\"indexable cpts\\\" to the debug info for easier troubleshooting<\\/li>\\r\\n<li>Fix: some PHP8 deprecation notices<\\/li>\\r\\n<li>Fix: hide the \\\"user selections\\\" area when empty<\\/li>\\r\\n<li>Fix: query detection issue involving SearchWP<\\/li>\\r\\n<li>Fix: added more reserved words for facet\\/listing names (automatically prefixed with underscore)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.8<\\/h4>\\r\\n<ul>\\r\\n<li>December 1, 2023<\\/li>\\r\\n<li>Fix: ACF \\\"button_group\\\" fields can now have labels too<\\/li>\\r\\n<li>Fix: query detection issue with SearchWP active<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.7<\\/h4>\\r\\n<ul>\\r\\n<li>November 8, 2023<\\/li>\\r\\n<li>Fix: mysqli notice for sites on WP 6.4+<\\/li>\\r\\n<li>Fix: ctype_digit() notice for sites on PHP 8.1+<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.6<\\/h4>\\r\\n<ul>\\r\\n<li>October 31, 2023<\\/li>\\r\\n<li>Improved: short-circuit SearchWP when \\\"s\\\" is empty and a search facet is in use<\\/li>\\r\\n<li>Improved: a11y - added `aria-label` attribute for number range facets<\\/li>\\r\\n<li>Fix: preloaded selections now appear in the \\\"User Selections\\\" box<\\/li>\\r\\n<li>Fix: JS error upon reset click for non-existant facets<\\/li>\\r\\n<li>Fix: support - replace \\\".php\\\" in plugin names to prevent Cloudflare from going haywire<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.5<\\/h4>\\r\\n<ul>\\r\\n<li>September 7, 2023<\\/li>\\r\\n<li>New: added \\\"ui_ghosts\\\" setting (needed for range_list and future facets)<\\/li>\\r\\n<li>Improved: improved main query detection for when query args are in a slightly different order<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.4<\\/h4>\\r\\n<ul>\\r\\n<li>August 3, 2023<\\/li>\\r\\n<li>Fix: issue preventing \\\"_builtin\\\" post types from indexing<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.3<\\/h4>\\r\\n<ul>\\r\\n<li>August 1, 2023<\\/li>\\r\\n<li>Improved: Star rating facet - added new UI color settings<\\/li>\\r\\n<li>Improved: enable \\\"Strict query detection\\\" by default for new installs<\\/li>\\r\\n<li>Fix: admin UI - row counts not updating after re-indexing<\\/li>\\r\\n<li>Fix: replaced default post_types from \\\"any\\\" to an actual array, for better WooCommerce compatibility<\\/li>\\r\\n<li>Fix: Listing builder - WooCommerce source field inconsistencies<\\/li>\\r\\n<li>Fix: WooCommerce - hid the `cf\\/_product_attributes` custom field, in favor of `cf\\/attribute_*`<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.2<\\/h4>\\r\\n<ul>\\r\\n<li>June 28, 2023<\\/li>\\r\\n<li>New: added `facetwp_scripts` WP action to manually add custom scripts<\\/li>\\r\\n<li>New: Proximity facet - added Placeholder field<\\/li>\\r\\n<li>Fix: better detection \\/ handling when `facetwp_pre_filtered_post_ids` or `facetwp_filtered_post_ids` hooks are in use<\\/li>\\r\\n<li>Fix: Date range - PHP warning when no end date is set (props Oscar M.)<\\/li>\\r\\n<li>Fix: WooCommerce - prevent issues for custom-translated stock statuses<\\/li>\\r\\n<li>Fix: more PHP8 deprecation notices<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.1<\\/h4>\\r\\n<ul>\\r\\n<li>June 5, 2023<\\/li>\\r\\n<li>Fix: `FWP()-&gt;is_filtered` should account for `facetwp_pre_filtered_post_ids` hook usage (fixes Advanced Woo Search)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.2.0<\\/h4>\\r\\n<ul>\\r\\n<li>May 17, 2023<\\/li>\\r\\n<li>Fix: admin - prevent caching of index table row counts<\\/li>\\r\\n<li>Fix: admin - plugin install notice listed the wrong add-on name (e.g. \\\"WPML\\\" instead of \\\"Multilingual\\\")<\\/li>\\r\\n<li>Fix: load more - prevent injecting results into static templates<\\/li>\\r\\n<li>Fix: indexer - issue causing index values for a post to clear on save<\\/li>\\r\\n<li>Improved: support - include memory stats<\\/li>\\r\\n<li>Improved: support - include whether Debug Mode is turned on<\\/li>\\r\\n<li><\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.9<\\/h4>\\r\\n<ul>\\r\\n<li>May 1, 2023<\\/li>\\r\\n<li>Improved: include `aria-label` for fSelect dropdowns<\\/li>\\r\\n<li>Fix: admin UI loading issues on Safari<\\/li>\\r\\n<li>Fix: possible undefined facet limits<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.8<\\/h4>\\r\\n<ul>\\r\\n<li>Apr 14, 2023<\\/li>\\r\\n<li>Improved: (re-)added notices when necessary integration add-ons are missing<\\/li>\\r\\n<li>Improved: admin UI - show the HTTP status code when an ajax request fails<\\/li>\\r\\n<li>Improved: migration script efficiency tweaks<\\/li>\\r\\n<li>Fix: Hierarchy facet - changed \\\"Count\\\" setting to \\\"Soft limit\\\" for consistency<\\/li>\\r\\n<li>Fix: Listing builder - switched button items back from HTML button to link elements<\\/li>\\r\\n<li>Fix: \\\"Show indexable post types\\\" UI setting now takes the `facetwp_indexer_query_args` hook into account<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.7<\\/h4>\\r\\n<ul>\\r\\n<li>Mar 20, 2023<\\/li>\\r\\n<li>Fix: PHP 8.2 \\\"AllowDynamicProperties\\\" deprecation notices (props Andrew M.)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.6<\\/h4>\\r\\n<ul>\\r\\n<li>Mar 6, 2023<\\/li>\\r\\n<li>Improved: autocomplete - support `facetwp_facet_display_value` hook<\\/li>\\r\\n<li>Improved: listing builder - use a &lt;form&gt; for button links (\\\"A\\\" tags around buttons is invalid HTML)<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.5<\\/h4>\\r\\n<ul>\\r\\n<li>Feb 7, 2023<\\/li>\\r\\n<li>New: added `facetwp_proximity_store_latlng` hook<\\/li>\\r\\n<li>Improved: listing builder - shortcode support for the \\\"No results text\\\" box<\\/li>\\r\\n<li>Improved: WooCommerce - renamed \\\"Include all products\\\" UI setting to \\\"Index out-of-stock products\\\"<\\/li>\\r\\n<li>Fix: ensure that `facetwp_get_distance` returns the closest distance when a post contains multiple locations<\\/li>\\r\\n<li>Fix: SearchWP - prevent extra escaped quotes<\\/li>\\r\\n<li>Fix: proximity - added the (now required) gmap `callback` argument<\\/li>\\r\\n<li>Fix: placeholder text not appearing for autocomplete and search facets<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.4<\\/h4>\\r\\n<ul>\\r\\n<li>Jan 16, 2022<\\/li>\\r\\n<li>New: added \\\"No results text\\\" field to the listing builder<\\/li>\\r\\n<li>Improved: WP-CLI integration - use temp table, just like the UI version<\\/li>\\r\\n<li>Fix: JSON response - ensure that \\\"action\\\" is a string (3rd party plugins sometimes break this standard)<\\/li>\\r\\n<li>Updated build tools<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.3<\\/h4>\\r\\n<ul>\\r\\n<li>Dec 15, 2022<\\/li>\\r\\n<li>Improved: data source dropdown - add taxonomy names after the labels (helps distinguish taxonomies sharing the same label)<\\/li>\\r\\n<li>Fix: listing builder - prevent double timezone offset<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.2<\\/h4>\\r\\n<ul>\\r\\n<li>Nov 10, 2022<\\/li>\\r\\n<li>Fix: query builder - \\\"EMPTY\\\" and \\\"NOT EMPTY\\\" clauses<\\/li>\\r\\n<li>Fix: ACF integration - prevent PHP8 error on invalid parent fields<\\/li>\\r\\n<li>Fix: typo with \\\"Strict query detection\\\" setting, please re-save if using that setting<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1.1<\\/h4>\\r\\n<ul>\\r\\n<li>Nov 4, 2022<\\/li>\\r\\n<li>New: added experimental \\\"Strict query detection\\\" UI setting<\\/li>\\r\\n<li>Improved: index table charset switched to utf8mb4 (for Emoji support)<\\/li>\\r\\n<li>Improved: date range - input labels can now be translated via facetwp_i18n<\\/li>\\r\\n<li>Improved: date range - a11y support<\\/li>\\r\\n<li>Fix: fSelect lib - fire a change event, even when the value is empty<\\/li>\\r\\n<li>Fix: a11y - added \\\"aria-hidden\\\" to hidden items to prevent ARIA warnings<\\/li>\\r\\n<li>Fix: the `facetwp_template_use_archive` hook should support the \\\"s\\\" argument<\\/li>\\r\\n<li>Fix: query builder - issue with the \\\"EXISTS\\\" \\/ \\\"NOT EXISTS\\\" query filter clauses<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.1<\\/h4>\\r\\n<ul>\\r\\n<li>October 4, 2022<\\/li>\\r\\n<li>Improved: tweaked admin UI styling<\\/li>\\r\\n<li>Improved: slider - prefix \\/ suffix fields are now translatable via `facetwp_i18n`<\\/li>\\r\\n<li>Improved: slider - better styling for the disabled state<\\/li>\\r\\n<li>Improved: fUtil lib now supports `.prepend`<\\/li>\\r\\n<li>Fix: checkboxes - choices ordered incorrectly when \\\"Preserve ghosts order\\\" was combined with \\\"Highest count\\\" sort<\\/li>\\r\\n<li>Fix: improved back-compat for the `get_filtered_post_ids` method<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.9<\\/h4>\\r\\n<ul>\\r\\n<li>Sept 15, 2022<\\/li>\\r\\n<li>Fix: query builder - issue when filtering by custom field values<\\/li>\\r\\n<li>Fix: listing builder - move `display: grid` CSS inline to prevent layout shifts<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.8<\\/h4>\\r\\n<ul>\\r\\n<li>Sept 7, 2022<\\/li>\\r\\n<li>Improved: revamped the \\\"User selections\\\" logic for number\\/date range facets<\\/li>\\r\\n<li>Improved: refined the sort logic, modified the new `facetwp_facet_sort_options` hook slightly<\\/li>\\r\\n<li>Improved: slider facet - display the UI even when only 1 available choice<\\/li>\\r\\n<li>Improved: customized noUiSlider.js lib to support `data-disabled` attribute (long story)<\\/li>\\r\\n<li>Improved: listing builder - added `post:title` dynamic tag<\\/li>\\r\\n<li>Improved: listing builder - renamed \\\"Name\\\" setting to \\\"Unique name\\\" and added tooltip<\\/li>\\r\\n<li>Improved: added label to range facet \\\"Compare type\\\" setting<\\/li>\\r\\n<li>Improved: fSelect lib - don\'t auto-focus the search box on touch devices<\\/li>\\r\\n<li>Improved: cache the row counts lookup<\\/li>\\r\\n<li>Fix: prevent PHP notices when indexing proximity facets (props @mgratch)<\\/li>\\r\\n<li>Fix: PHP notice caused by undefined `$exists_clause`<\\/li>\\r\\n<li>Fix: fSelect \\\"No results\\\" text wasn\'t appearing<\\/li>\\r\\n<li>Fix: reset facet didn\'t reset pager or sort<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.7<\\/h4>\\r\\n<ul>\\r\\n<li>August 25, 2022<\\/li>\\r\\n<li>New: `facetwp_facet_sort_options` hook for Sort facets (mimics behavior of the \\\"old\\\" sort feature)<\\/li>\\r\\n<li>Improved: display WP compatibility data for update checks<\\/li>\\r\\n<li>Improved: auto-ignore \\\"nav_menu_item\\\" and \\\"wp_block\\\" post types<\\/li>\\r\\n<li>Improved: number range - when input is focused, Enter key now triggers a refresh<\\/li>\\r\\n<li>Fix: fComplete library - prefix the \\\"hidden\\\" class to prevent conflicts<\\/li>\\r\\n<li>Fix: PHP error when using the API `fetch` method<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.6<\\/h4>\\r\\n<ul>\\r\\n<li>August 15, 2022<\\/li>\\r\\n<li>Improved: refactored sort logic<\\/li>\\r\\n<li>Improved: multisite update notification support<\\/li>\\r\\n<li>Improved: a11y - allow for translations of pager-related ARIA attributes<\\/li>\\r\\n<li>Improved: query builder - added `EMPTY` and `NOT EMPTY` clauses to the query filter UI<\\/li>\\r\\n<li>Fix: admin UI styling tweaks (font sizes)<\\/li>\\r\\n<li>Updated translations<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.5<\\/h4>\\r\\n<ul>\\r\\n<li>July 22, 2022<\\/li>\\r\\n<li>Improved: Query builder styling tweaks<\\/li>\\r\\n<li>Improved: value modifiers UI setting supports both HTML entities (e.g. &amp; copy;) and symbols (e.g. \\u00a9)<\\/li>\\r\\n<li>Fix: prevent scrollbar shift when using the actions popup (on the facet\\/template listing screens)<\\/li>\\r\\n<li>Fix: layout builder - `date_format` and `input_format` settings should have a default value<\\/li>\\r\\n<li>Fix: prevent manual indexing issues when the `facetwp_indexer_is_enabled` hook is false<\\/li>\\r\\n<li>Updated VueJS, SortableJS, noUiSlider, and vue-select<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.4<\\/h4>\\r\\n<ul>\\r\\n<li>July 5, 2022<\\/li>\\r\\n<li>Fix: prevent facets from being named `labels` to prevent issues<\\/li>\\r\\n<li>Fix: ignore non-facet (i.e. custom) fSelects<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.3<\\/h4>\\r\\n<ul>\\r\\n<li>June 6, 2022<\\/li>\\r\\n<li>New: slider facets - added \\\"Reset text\\\" UI setting<\\/li>\\r\\n<li>Improved: admin - only show \\\"Compare type\\\" setting when \\\"Other data source\\\" is used<\\/li>\\r\\n<li>Fix: formatting bug preventing sliders from loading properly<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.2<\\/h4>\\r\\n<ul>\\r\\n<li>May 31, 2022<\\/li>\\r\\n<li>New: `facetwp_builder_query_data` hook<\\/li>\\r\\n<li>Improved: proximity facets are now up to 40x faster (props And)<\\/li>\\r\\n<li>Improved: slider - support \\\"Enclose\\\" compare type<\\/li>\\r\\n<li>Improved: added `FWP.response` JS object containing ajax response data<\\/li>\\r\\n<li>Improved: Query builder - better styling of vue-select (dropdown) inputs<\\/li>\\r\\n<li>Improved: apply `facetwp_facet_display_value` hook to dropdown and fselect facets<\\/li>\\r\\n<li>Fix: moved the `facetwp\\/set_options\\/slider` JS hook (allows for \\\"range\\\" to be overriden)<\\/li>\\r\\n<li>Fix: admin - prevent 3rd party menus from moving the top nav bar<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0.1<\\/h4>\\r\\n<ul>\\r\\n<li>May 2, 2022<\\/li>\\r\\n<li>Improved: admin UI - display facet \\/ template names in the list tables<\\/li>\\r\\n<li>Improved: support value-less shortcode atts, e.g. `[facetwp template=\\\"test\\\" static]`<\\/li>\\r\\n<li>Fix: prevent reset facets from resetting other reset facets (reset-ception)<\\/li>\\r\\n<li>Fix: sort facet - make default label translatable via `facetwp_i18n` hook<\\/li>\\r\\n<li>Fix: CSS issue when using multiple FacetWP (shortcode) listings on a page<\\/li>\\r\\n<li>Fix: CSS issue preventing listing builder\'s default 1-column mobile layout<\\/li>\\r\\n<li>Fix: restore a11y compat for the \\\"old\\\" sort feature<\\/li>\\r\\n<li>Fix: counts shortcode display issue when per_page = -1<\\/li>\\r\\n<li>Fix: cast page numbers as `int` for FWP()-&gt;facet-&gt;pager_args<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<h4>4.0<\\/h4>\\r\\n<ul>\\r\\n<li>Apr 18, 2022<\\/li>\\r\\n<li>Important: FacetWP 4.0 requires PHP 7.0 or above<\\/li>\\r\\n<li>New: <a href=\\\"https:\\/\\/facetwp.com\\/help-center\\/facets\\/facet-types\\/reset\\/\\\" target=\\\"_blank\\\">Reset facets<\\/a><\\/li>\\r\\n<li>New: support for WP Rocket<\\/li>\\r\\n<li>New: support for multiple (static) FacetWP templates on a page<\\/li>\\r\\n<li>New: ability to duplicate facets\\/templates from the admin listing<\\/li>\\r\\n<li>New: ability to copy facet\\/template shortcodes from the admin listing<\\/li>\\r\\n<li>New: added `post:image` dynamic tag to the Listing Builder<\\/li>\\r\\n<li>New: `facetwp_facet_pager_link` hook to customize the pager output<\\/li>\\r\\n<li>Improved: much better Listing Builder admin UI<\\/li>\\r\\n<li>Improved: tweaked the order of the \\\"Data source\\\" options<\\/li>\\r\\n<li>Improved: added `span` around checkbox \\/ radio display values<\\/li>\\r\\n<li>Improved: admin.css uses CSS variables to standardize colors<\\/li>\\r\\n<li>Improved: better admin UI tooltip help text<\\/li>\\r\\n<li>Improved: a11y - better support for pager and sort facets<\\/li>\\r\\n<li>Improved: pager - \\\"Per page\\\" facets support a \\\"Show All\\\" option<\\/li>\\r\\n<li>Improved: facetwp_display() now supports an optional 3rd argument ($atts)<\\/li>\\r\\n<li>Improved: allow sort labels to be translated using `facetwp_i18n`<\\/li>\\r\\n<li>Improved: made the admin tooltip UI less subtle<\\/li>\\r\\n<li>Improved: renamed \\\"Templates\\\" to \\\"Listings\\\"<\\/li>\\r\\n<li>Fix: sort facet choices by depth only when hierarchical<\\/li>\\r\\n<li>Fix: sort facets should override the default relevancy sort when in use<\\/li>\\r\\n<li>Fix: autocomplete - the UI should adhere to the `facetwp_facet_autocomplete_limit` hook<\\/li>\\r\\n<li>Fix: star rating facets work with the \\\"Hide empty facets\\\" tutorial<\\/li>\\r\\n<li>Fix: issue with multiple EDD `[downloads]` shortcodes on a page<\\/li>\\r\\n<li>Fix: remove Reset and Sort facets from the \\\"User selections\\\" list<\\/li>\\r\\n<li>Fix: prevent duplicate refreshes when using custom fSelect elements<\\/li>\\r\\n<li>Fix: fSelect - when \\\"Hierarchical\\\" setting is off, ignore depth to prevent display issues<\\/li>\\r\\n<li>Updated noUiSlider<\\/li>\\r\\n<li>Updated package.json<\\/li>\\r\\n<\\/ul>\"},\"package\":\"\",\"downloaded\":0,\"url\":\"https:\\/\\/facetwp.com\",\"homepage\":\"https:\\/\\/facetwp.com\\/\",\"contributors\":{\"mgibbs189\":{\"profile\":\"\",\"avatar\":\"https:\\/\\/secure.gravatar.com\\/avatar\\/ce6607d5fb834cbfc538bce124e8ddd3?s=96&d=monsterid\",\"display_name\":\"Matt Gibbs\"}}}}','off');
