:3:\"6.1\";s:12:\"requires_php\";s:3:\"7.1\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:74;s:11:\"num_ratings\";i:23;s:15:\"support_threads\";i:3;s:24:\"support_threads_resolved\";i:0;}s:39:\"wp-file-manager/file_folder_manager.php\";O:8:\"stdClass\":17:{s:2:\"id\";s:29:\"w.org/plugins/wp-file-manager\";s:4:\"slug\";s:15:\"wp-file-manager\";s:6:\"plugin\";s:39:\"wp-file-manager/file_folder_manager.php\";s:11:\"new_version\";s:5:\"8.0.4\";s:3:\"url\";s:46:\"https://wordpress.org/plugins/wp-file-manager/\";s:7:\"package\";s:71:\"https://plugin-updates.wpengine.com/wp-file-manager/wp-file-manager.zip\";s:5:\"icons\";a:1:{s:2:\"1x\";s:75:\"https://plugin-updates.wpengine.com/wp-file-manager/assets/icon-128x128.png\";}s:7:\"banners\";a:2:{s:3:\"low\";s:89:\"https://plugin-updates.wpengine.com/wp-file-manager/assets/banner-772x250.jpg?rev=2491299\";s:4:\"high\";b:0;}s:11:\"banners_rtl\";a:0:{}s:6:\"tested\";s:5:\"6.9.4\";s:8:\"requires\";s:3:\"4.0\";s:12:\"requires_php\";s:5:\"5.2.4\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:94;s:11:\"num_ratings\";i:1467;s:15:\"support_threads\";i:2;s:24:\"support_threads_resolved\";i:0;}s:17:\"facetwp/index.php\";O:8:\"stdClass\":6:{s:4:\"slug\";s:7:\"facetwp\";s:6:\"plugin\";s:17:\"facetwp/index.php\";s:11:\"new_version\";s:3:\"4.5\";s:7:\"package\";s:0:\"\";s:8:\"requires\";s:3:\"5.0\";s:6:\"tested\";s:5:\"6.9.4\";}}s:7:\"checked\";a:11:{s:34:\"advanced-custom-fields-pro/acf.php\";s:5:\"6.8.1\";s:19:\"akismet/akismet.php\";s:3:\"5.7\";s:17:\"facetwp/index.php\";s:3:\"4.5\";s:33:\"genesis-blocks/genesis-blocks.php\";s:5:\"3.1.8\";s:45:\"varner-os-plugin-v23/varner-os-plugin-v23.php\";s:6:\"1.23.0\";s:45:\"varner-simple-backup/varner-simple-backup.php\";s:5:\"1.0.0\";s:39:\"wp-all-export-pro/wp-all-export-pro.php\";s:6:\"1.9.15\";s:39:\"wp-all-import-pro/wp-all-import-pro.php\";s:5:\"5.0.6\";s:39:\"wp-file-manager/file_folder_manager.php\";s:5:\"8.0.4\";s:23:\"wp-rocket/wp-rocket.php\";s:6:\"3.21.1\";s:40:\"wordpress-seo-p