INSERT INTO `wp_options` VALUES ('2122','wp-all-import-pro_85b8495febade7a221f67b0bca7d59d9','O:8:\"stdClass\":19:{s:11:\"new_version\";s:5:\"5.0.6\";s:14:\"stable_version\";s:5:\"5.0.6\";s:4:\"name\";s:13:\"WP All Import\";s:4:\"slug\";s:17:\"wp-all-import-pro\";s:6:\"plugin\";s:39:\"wp-all-import-pro/wp-all-import-pro.php\";s:3:\"url\";s:68:\"https://www.wpallimport.com/downloads/wp-all-import-pro/?changelog=1\";s:12:\"last_updated\";s:19:\"2026-04-08 13:18:57\";s:8:\"homepage\";s:56:\"https://www.wpallimport.com/downloads/wp-all-import-pro/\";s:8:\"sections\";a:2:{s:11:\"description\";s:216:\"<p>Learn more about WP All Import at <a href=\"https://www.wpallimport.com/import-wordpress-csv-xml-excel/\" target=\"_blank\" rel=\"noopener noreferrer\">https://www.wpallimport.com/import-wordpress-csv-xml-excel/</a></p>\";s:9:\"changelog\";s:61552:\"<h4>5.0.6</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: feed type detection could incorrectly identify XML, JSON, and gzip feeds as CSV, causing imports to fail</li>\r\n</ul><h4>5.0.5</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: AWIN datafeeds with path-based gzip compression hints (e.g. /compression/gzip/) failed to import</li>\r\n<li>bug fix: XLS and XLSX feeds served from URLs without file extensions were not importable</li>\r\n<li>bug fix: stale feed type stored in the database could cause feeds to re-import with the wrong format on subsequent runs</li>\r\n<li>bug fix: import and template page buttons displayed incorrect styling in WordPress 7.0 RC</li>\r\n<li>improvement: feed type detection now uses magic bytes for reliable handling of feeds that lack file extensions or correct HTTP headers</li>\r\n<li>improvement: eliminated redundant HEAD request for unknown-type URLs, preventing failures on rate-limited feeds</li>\r\n</ul>\r\n<h4>5.0.5</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: AWIN datafeeds with path-based gzip compression hints (e.g. /compression/gzip/) failed to import</li>\r\n<li>bug fix: XLS and XLSX feeds served from URLs without file extensions were not importable</li>\r\n<li>bug fix: stale feed type stored in the database could cause feeds to re-import with the wrong format on subsequent runs</li>\r\n<li>bug fix: import and template page buttons displayed incorrect styling in WordPress 7.0 RC</li>\r\n<li>improvement: feed type detection now uses magic bytes for reliable handling of feeds that lack file extensions or correct HTTP headers</li>\r\n<li>improvement: eliminated redundant HEAD request for unknown-type URLs, preventing failures on rate-limited feeds</li>\r\n</ul>\r\n<h4>5.0.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security fix: CVE-2026-2830</li>\r\n<li>bug fix: fatal error when activating Pro while Free version is active</li>\r\n<li>bug fix: fatal error when downloading import bundle with URL feed</li>\r\n<li>bug fix: drag and drop now respects cursor position in text areas</li>\r\n<li>bug fix: private taxonomies option no longer resets when editing template</li>\r\n<li>bug fix: Excel formulas now show calculated value instead of formula text</li>\r\n<li>bug fix: PHP 8.1+ deprecation notice for auto_detect_line_endings</li>\r\n</ul>\r\n<h4>5.0.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security fix: CVE-2026-2830</li>\r\n<li>bug fix: fatal error when activating Pro while Free version is active</li>\r\n<li>bug fix: fatal error when downloading import bundle with URL feed</li>\r\n<li>bug fix: drag and drop now respects cursor position in text areas</li>\r\n<li>bug fix: private taxonomies option no longer resets when editing template</li>\r\n<li>bug fix: Excel formulas now show calculated value instead of formula text</li>\r\n<li>bug fix: PHP 8.1+ deprecation notice for auto_detect_line_endings</li>\r\n</ul>\r\n<h4>5.0.3</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: IE deprecation notice in WP 6.9</li>\r\n</ul><h4>5.0.2</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: refine import preview flow</li>\r\n<li>improvement: add intelligent handling for imported Gutenberg blocks</li>\r\n<li>improvement: bypass unsaved change warning during import previews</li>\r\n<li>bug fix: undefined index for preload_images option</li>\r\n</ul><h4>5.0.1</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: resolve error when migrating galleries in certain cases</li>\r\n</ul><h4>5.0.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>new feature: import previews</li>\r\n<li>bug fix: restore gallery migration support</li>\r\n<li>bug fix: preserve legitimate double quotes from Excel files</li>\r\n<li>maintenance: update PhpSpreadsheet and phpseclib</li>\r\n</ul><h4>4.11.7</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: upgrade svg-sanitize library</li>\r\n</ul><h4>4.11.6</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security improvement: fixes CVE-2025-10001</li>\r\n<li>improvement: upgrade PhpSpreadsheet version</li>\r\n</ul><h4>4.11.5</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: import settings file upload doesn\'t work</li>\r\n</ul><h4>4.11.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: streamlined new/existing items UI</li>\r\n<li>improvement: add alternative Excel processing for files that fail with PhpSpreadsheet</li>\r\n<li>improvement: add drag and drop file uploads to step 1 of a new import</li>\r\n</ul><h4>4.11.3</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: add partner discounts</li>\r\n<li>bug fix: resolve textdomain notices</li>\r\n</ul><h4>4.11.2</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: streamlined \'new import\' flow to make filter configuration step optional</li>\r\n<li>bug fix: taxonomy \'only add new\' option only works with 1 record per iteration</li>\r\n</ul><h4>4.11.1</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: don\'t set defaults for TEXT db fields</li>\r\n</ul><h4>4.11.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security improvement: migrate from PHPExcel to PhpSpreadsheet</li>\r\n<li>API: add \'pmxi_accept_header\' filter</li>\r\n<li>improvement: UI updates</li>\r\n</ul><h4>4.10.1</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>integration: support sending Function Editor code to WPCodeBox</li>\r\n<li>API: add \'pmxi_mimic_browser_user_agent\' filter</li>\r\n<li>API: add \'pmxi_user_agent\' filter</li>\r\n<li>bug fix: \'current_xml_node\' value is missing for image filters in some cases</li>\r\n<li>bug fix: type error in rare cases when uploading Excel file</li>\r\n</ul><h4>4.10.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>API: add pmxi_content_image action</li>\r\n<li>improvement: UI updates</li>\r\n<li>improvement: prioritize XML in the Accept list when downloading files</li>\r\n<li>bug fix: non-SVG images are passed to SVG sanitizer in some cases</li>\r\n</ul><h4>4.9.11</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: terms without parent aren\'t matched correctly</li>\r\n</ul><h4>4.9.10</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: updater class isn\'t called when updating plugins via WP-CLI</li>\r\n<li>bug fix: fatal error when deleting missing records</li>\r\n</ul><h4>4.9.9</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: taxonomy terms are sometimes not found by slug</li>\r\n<li>bug fix: SQL query failure due to query length in rare cases when using \'change missing\' option</li>\r\n<li>bug fix: add-ons cannot set featured image/thumbnail in some cases</li>\r\n</ul><h4>4.9.8</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security improvement, fixes: CVE-2024-8722, CVE-2024-9664, CVE-2024-9661</li>\r\n</ul><h4>4.9.7</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: use descriptive user agent string when downloading files</li>\r\n<li>bug fix: taxonomy terms are matched to the wrong parent in some cases</li>\r\n</ul><h4>4.9.6</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: add setting to control file download timeout</li>\r\n<li> bug fix: premature file download timeout in some cases</li>\r\n<li> bug fix: automatically attempt to match terms by name if term_exists() check fails</li>\r\n<li>bug fix: Scheduling license check fails with a fatal error in some cases</li>\r\n</ul><h4>4.9.5</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: image downloads hang indefinitely in rare cases</li>\r\n<li>bug fix: use expanded validation for all existing term matching</li>\r\n</ul><h4>4.9.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security improvement</li>\r\n<li>improvement: get list of supported image types from WP and explicitly support AVIF images if available</li>\r\n<li>bug fix: base64 gallery images in content cannot be imported</li>\r\n<li>bug fix: truncate generated term slugs that exceed WP length limit</li>\r\n<li>bug fix: fatal error with the French translation</li>\r\n<li>bug fix: fatal error if file chunk isn\'t found</li>\r\n<li>bug fix: only enable preloading images when using the option to download images</li>\r\n<li>bug fix: use first imported content image as featured if no other images are set</li>\r\n<li>bug fix: don\'t show PHP notice when \'allow_delay_image_processing\' option doesn\'t exist in add-on</li>\r\n</ul><h4>4.9.3</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: default to disabling delayed image processing</li>\r\n</ul><h4>4.9.2</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: restore missing regenerate_thumbnails_sql method</li>\r\n</ul><h4>4.9.1</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: add cron key to Scheduling API calls for future use</li>\r\n<li>improvement: optimize WooCommerce product image imports</li>\r\n<li>improvement: add-on API updated to support JetEngine Relations when used with the latest JE add-on</li>\r\n<li>improvement: updated Spanish and French translations</li>\r\n<li>improvement: removed all broken translations</li>\r\n<li>improvement: added option to \'auto-retry\' manual imports on failure</li>\r\n<li>improvement: allow delayed image processing for all post types</li>\r\n<li>bug fix: ignore brackets within strings when validating Function Editor code</li>\r\n<li>bug fix: attachments parameter should always be an array</li>\r\n<li>bug fix: add-ons not matching images by filename in some cases</li>\r\n<li>bug fix: error \'Cannot use object of type WP_Error as array\' in some cases</li>\r\n<li> bug fix: attempt to set proper image extension if extension is missing</li>\r\n<li>bug fix: \'wp_all_import_single_image_uploads_dir\' filter not applied to addon images</li>\r\n<li> bug fix: base64 encoded images in content are not imported correctly</li>\r\n</ul><h4>4.9.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: validate Function Editor code against PHP 7.x or PHP 8.x based on running version of PHP</li>\r\n<li>improvement: replace invalid records per iteration values with default of 20</li>\r\n<li>improvement: add geocoding support to new Add-On API</li>\r\n<li>bug fix: drag and drop not working for some fields</li>\r\n<li>bug fix: ensure add-on images are checked by _wp_attached_file if not set to download</li>\r\n<li>bug fix: imports sometimes hang on images that cannot be downloaded</li>\r\n<li>bug fix: only add new taxonomies option doesn\'t work</li>\r\n<li>bug fix: fatal error in some cases when importing comments</li>\r\n<li>bug fix: encoded term slugs incorrectly matched in some cases</li>\r\n<li>bug fix: function editor parenthesis in strings can lead to validation failures</li>\r\n<li>bug fix: SVGs aren\'t handled correctly in some cases</li>\r\n</ul><h4>4.8.10</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: Function Editor on Settings page doesn\'t load</li>\r\n</ul><h4>4.8.9</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: use main Image section\'s existing image matching settings for add-ons using the original API</li>\r\n<li>improvement: use jQuery based drag and drop</li>\r\n<li>improvement: update new add-on API to enable support for non-post-type imports</li>\r\n<li>improvement: purge invalid WP All Import session data</li>\r\n<li>improvement: update phpseclib</li>\r\n<li>bug fix: ‘change missing’ endless loop when targeting all products with variations and changing to \'trash\' or \'draft\' status</li>\r\n<li>bug fix: allow using \'Enter\' in textarea fields</li>\r\n<li>bug fix: delete/change missing \'users\' doesn\'t work in some cases</li>\r\n<li>bug fix: only products are searched when matching comments to their parents by title</li>\r\n</ul><h4>4.8.8</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: remove unused moment.js</li>\r\n<li>improvement: do not trigger saving template or import settings pages when pressing \'Enter\'</li>\r\n<li>bug fix: FTP \'newest\' and \'oldest\' not excluding folders when locating target for download</li>\r\n<li>bug fix: incorrect FTP timestamps for files less than 6 months old which were last modified last year</li>\r\n<li>bug fix: post author is set to any user named \'admin\' when no author is provided when running via cron or WP-CLI</li>\r\n<li>bug fix: don\'t store base64 encoded images from content in *pmxi_images table</li>\r\n<li>bug fix: resolve dynamic property notices in UniqueNode class</li>\r\n<li>bug fix: option to specify fields to update doesn\'t work for JetEngine and Meta Box add-ons</li>\r\n<li>bug fix: apply options to delete images and attachments to variations when bulk deleting imported products</li>\r\n<li>bug fix: all fields are updated when specific fields are listed for update in JetEngine and Meta Box add-ons</li>\r\n<li>bug fix: add support for non-image files to media fields in the add-on API</li>\r\n<li>bug fix: ensure chunk file was opened before trying to use file functions on it</li>\r\n<li>bug fix: fatal error in PHP 8+ for some JSON feeds</li>\r\n<li>bug fix: use correct slugs for add-on changelogs and update requests</li>\r\n<li>bug fix: revert to old line ending behavior when reading CSV files in PHP 8.1+</li>\r\n</ul><h4>4.8.7</h4><ul>\r\n<li>fix: restore PHP 7.4 compatibility</li>\r\n<li>fix: new add-on API doesn\'t work with WP-CLI</li>\r\n<li>fix: deleting missing users hangs if there are admin users in the iteration</li>\r\n<li>fix: do not fire \'wp_all_import_force_cron_processing_on_empty_feed\' filter unless no file exists</li>\r\n<li>fix:\"Could not set timer\" fatal error with PHP 8.3.2</li>\r\n<li>fix: fatal error when history log isn\'t writable</li>\r\n</ul><h4>4.8.6</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>API: first version of new add-on API - existing rapid add-on API is still fully functional</li>\r\n<li>API: added ‘wp_all_import_is_post_to_change_missing’ filter</li>\r\n<li>bug fix: run imports to completion when ‘wp_all_import_force_cron_processing_on_empty_feed’ filter returns ‘true’</li>\r\n<li>bug fix: download fails when Content-Disposition headers are duplicated</li>\r\n<li>bug fix: valid downloads sometimes fail on very large imports</li>\r\n<li>bug fix: ‘history file not found’ message on valid file</li>\r\n<li>bug fix: undefined variable $image_name</li>\r\n<li>bug fix: custom fields section not working properly with WooCommerce HPOS</li>\r\n<li>bug fix: fatal error in some cases when SFTP connection attempt fails</li>\r\n<li>bug fix: orders incorrectly matched when empty meta value provided for matching</li>\r\n<li>bug fix: fatal error in PHP 8.2 related to ‘_update_posts_count_on_transition_post_status’</li>\r\n<li>bug fix: fatal error in some cases when re-running imports with WooCommerce HPOS</li>\r\n<li>bug fix: image fails to import if there is a hyphen before the extension</li>\r\n<li>bug fix: HTML imported to taxonomy description is incorrectly encoded</li>\r\n<li>bug fix: SFTP fails when FTP module isn’t installed in PHP</li>\r\n<li>bug fix: WooCommerce Order emails not blocked </li>\r\n<li>improvement: improved Scheduling service connection check accuracy</li>\r\n<li>improvement: hover over taxonomies in dropdown to see their slugs</li>\r\n</ul><h4>4.8.5</h4><ul>\r\n<li>improvement: ensure temporary files never use a .php extension</li>\r\n<li>bug fix: restore old CSV encoding conversion behavior</li>\r\n<li>bug fix: orders cannot be matched by order meta</li>\r\n<li>bug fix: SFTP imports fail to run via cron in some cases</li>\r\n</ul><h4>4.8.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.2</li>\r\n<li>bug fix: do not automatically deactivate old versions of the WooCommerce Import Add-On</li>\r\n</ul><h4>4.8.3</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.2</li>\r\n<li>bug fix: PHP 8.2 fatal error when importing some Excel files</li>\r\n<li>bug fix: PHP 8.2 fatal error when file cannot be written in some cases</li>\r\n</ul><h4>4.8.2</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.2</li>\r\n<li>note: WooCommerce Import Add-On 4.0.0+ is required to import orders</li>\r\n<li>new setting: add \'Do not create new terms\' setting on Edit Template page</li>\r\n<li>improvement: better PHP 8.2 support</li>\r\n<li>improvement: include example cron commands on Scheduling Options modal</li>\r\n<li>improvement: better import file preview loading</li>\r\n<li>improvement: enable updating taxonomy description image URLs when using \'Scan through post content...\' option</li>\r\n<li>improvement: enable matching review products by title</li>\r\n<li>improvement: replace tmpfile() call with wp_tempnam() to avoid host restrictions</li>\r\n<li>bug fix: preview modal isn\'t scrollable in some cases</li>\r\n<li>bug fix: resolve \'change missing\' loop in some cases when products have backorders enabled</li>\r\n<li>bug fix: resolve fatal error when taxonomies are set to update but the WooCommerce Add-On isn\'t active</li>\r\n<li>bug fix: navigating import file preview shows incorrectly numbered records</li>\r\n</ul><h4>4.8.1</h4><ul>\r\n<li> minimum required WP version: 5.0</li>\r\n<li> minimum required PHP version: 7.2.5</li>\r\n<li> improvement: remove wp_navigation from Step 1 dropdown</li>\r\n<li> improvement: fix PHP 8 deprecated notice</li>\r\n<li> improvement: add new filter \'wp_all_import_hash_ignore_options\' </li>\r\n<li> bug fix: match existing terms by ID</li>\r\n<li> bug fix: ensure records added with an \'Existing Items\' import are recognized by the options to modify missing records</li>\r\n<li> bug fix: ensure \"History file not found\' message doesn\'t remain when file is valid</li>\r\n<li> bug fix: avoid fatal error while editing import when import file has been deleted outside of WP All Import</li>\r\n<li> bug fix: ensure correct import IDs are processed when running multiple imports sequentially via WP-CLI</li>\r\n<li> bug fix: don\'t invalidate unchanged record hash when import \'security\' option value changes</li>\r\n<li> bug fix: allow using an \'Existing Items\' import that only removes products that aren\'t in the import file</li>\r\n</ul><h4>4.8.0</h4><ul>\r\n    <li>bug fix: file preview shows incorrect record order in some cases</li>\r\n    <li>bug fix: PHP8 fatal error when updating Scheduling configuration in limited cases</li>\r\n</ul><h4>4.7.9</h4><ul>\r\n    <li>new feature: edit import filters on import \'Edit Template\' screen</li>\r\n    <li>bug fix: allow saving custom fields \'0\' values</li>\r\n    <li>bug fix: do not duplicate images when they contain dimensions in the name</li>\r\n    <li>bug fix: infinite loop when performing \'missing post\' actions in some cases</li>\r\n    <li>bug fix: undefined variable $import notice</li>\r\n    <li>bug fix: resolve notice when $attch variable not defined</li>\r\n    <li>improvement: use wp_trash_post when sending posts to trash</li>\r\n    <li>improvement: resolve PHP 8.x deprecated items</li>\r\n    <li>improvement: allow more strings to be translated with _e</li>\r\n    <li>improvement: use wp_add_inline_script instead of localize where appropriate</li>\r\n    <li>improvement: add setting to disable the \'I HAVE BACKUPS\' prompt</li>\r\n    <li>improvement: better handling when expected files are not found or have the wrong permissions</li>\r\n    <li>improvement: ensure the run import screen correctly shows what fields are set to update</li>\r\n    <li>improvement: add nonce to clean up logs action</li>\r\n    <li>improvement: allow specifying templates for post types other than pages</li>\r\n    <li>improvement: replace deprecated get_page_by_title function</li>\r\n    <li>improvement: ensure correct version of PCLZIP is used with WP All Import</li>\r\n    <li>improvement: ensure history file path returns correctly regardless of import file source</li>\r\n    <li>improvement: ensure wp_read_video_metadata function exists before calling</li>\r\n    <li>improvement: ensure import file preview sections can be expanded on Edit Template screen</li>\r\n    <li>improvement: allow changing stock status for missing existing products</li>\r\n    <li>improvement: call pmxi_before_delete_post hook as needed when running via WP-CLI</li>\r\n    <li>improvement: don\'t show \'hidden\' imports when listing via WP-CLI</li>\r\n    <li>improvement: don\'t assign parent when parent field is empty</li>\r\n    <li>improvement: allow importing emojis from JSON files</li>\r\n    <li>improvement: improve wp_all_import_get_import_id to work when running multiple imports via WP-CLI</li>\r\n    <li>improvement: better record matching for delete missing option</li>\r\n    <li>improvement: better existing image matching when importing images from Content</li>\r\n\r\n</ul><h4>4.7.8</h4><ul>\r\n    <li>new feature: Records missing from your import file can now be deleted even if WP All Import didn\'t create them. \'Existing Items\' imports have gained the ability to delete records missing from your import file as well.</li>\r\n    <li>improvement: add support for libxml 2.9.0+</li>\r\n    <li>improvement: set headers to prevent caching of cron URLs</li>\r\n    <li>improvement: fixed miscellaneous PHP notices</li>\r\n</ul>\r\n<h4>4.7.7</h4><ul>\r\n    <li>security improvement</li>\r\n    <li>improvement: import progress bar appearance</li>\r\n</ul><h4>4.7.6</h4><ul>\r\n    <li>security improvement</li>\r\n    <li>note: minimum PHP version for WP All Import 4.7.4 and above is now 7.2.5</li>\r\n    <li>bug fix: fatal error when PHP version is less than 7.2.5</li>\r\n    <li>improvement: replace deprecated jQuery functions</li>\r\n    <li>improvement: add support for newer SFTP servers</li>\r\n    <li>improvement: update FTP support for PHP 8.1+</li>\r\n    <li>improvement: better file extension detection for downloaded attachments</li>\r\n</ul><h4>4.7.5</h4><ul>\r\n<li>bug fix: fatal error when importing from (S)FTP</li>\r\n</ul><h4>4.7.4</h4><ul>\r\n  <li>security improvement</li>\r\n  <li>bug fix: error when importing tab delimited text files on PHP 8</li>\r\n  <li>bug fix: ensure wp_read_video_metadata() function is available before calling it</li>\r\n  <li>improvement: better autoloading of plugin files</li>\r\n  <li>improvement: better handling for server paths that contain underscores</li>\r\n  <li>improvement: fix notice when downloading from Google Sheets</li>\r\n</ul><h4>4.7.3</h4><ul>\r\n    <li>improvement: changed Manage Imports page button labels to be more precise</li>\r\n    <li>improvement: assign \'Uncategorized\' term to posts imported without a category assigned</li>\r\n    <li>improvement: add support for taxonomies that return objects instead of IDs</li>\r\n    <li>improvement: check if import file still exists before trying to load it</li>\r\n    <li>improvement: remove commented code that could cause false positives for security scans</li>\r\n    <li>bug fix: jQuery error related to \'destroy\' method</li>\r\n    <li>bug fix: rare issue that prevented content image URLs from being updated during import</li>\r\n    <li>bug fix: option to mark missing products as out of stock doesn\'t work with cron</li>\r\n    <li>bug fix: taxonomies section drag and drop doesn\'t save after rearranging fields</li>\r\n    <li>bug fix: can\'t save code to Function Editor</li>\r\n    <li>bug fix: conflict with Advanced Ads plugin</li>\r\n</ul><h4>4.7.2</h4><ul>\r\n<li>bug fix: \'Set missing records to out of stock\' option doesn\'t work when \'Delete products that are no longer present in your file\' option enabled</li>\r\n<li>bug fix: do not invalidate hash when FTP settings change</li>\r\n<li>bug fix: drag-and-drop hierarchical taxonomies doesn\'t work ( WordPress 5.9 )</li>\r\n<li>improvement: respect filename matching options with images in content</li>\r\n</ul><h4>4.7.1</h4><ul>\r\n<li>security fix</li>\r\n<li>improvement: add support for extremely long image source URLs</li>\r\n<li>improvement: invalidate \'skip records that haven\'t changed\' hash when using the \'instead of delete\' options</li>\r\n<li>bug fix: file cleanup fails on PHP 8</li>\r\n</ul><h4>4.7.0</h4>\r\n<ul>\r\n    <li>bugfix: ensure that invalid Automatic Scheduling times aren\'t supplied by import template</li> \r\n    <li>improvement: add ability to control taxonomy mapping case sensitivity via filter wpai_is_case_insensitive_taxonomy_mapping</li> \r\n    <li>improvement: add ability to control uploads directory for single file/image via filters wp_all_import_single_image_uploads_dir and wp_all_import_single_attachment_uploads_dir</li>  \r\n    <li>improvement: add missing options on confirm import step</li> \r\n    <li>improvement: decrease frequency of plugin updates check</li> \r\n    <li>bug fix</li>\r\n    <li>improvement: initial PHP 8 support</li>\r\n</ul>    \r\n<h4>4.6.9</h4>\r\n<ul>\r\n 	<li>bug fix: categories were imported despite the taxonomy option being disabled</li>\r\n 	<li>improvement: ssl_verify was disabled for api requests</li>\r\n 	<li>improvement: parent review setting was missing when importing WooCommerce Reviews</li>\r\n 	<li>improvement: add ability to filter csv escape symbol via wp_all_import_csv_parser_settings filter</li>\r\n</ul>\r\n<h4>4.6.8</h4>\r\n<ul>\r\n 	<li>maintenance: compatibility with Elementor v3.3 JavaScript changes</li>\r\n</ul>\r\n<h4>4.6.7 2021-05-21</h4>\r\n<ul>\r\n 	<li>bug fix: import of taxonomies hierarchy didn\'t work properly</li>\r\n</ul>\r\n<h4>4.6.6 2021-05-18</h4>\r\n<ul>\r\n 	<li>bug fix: records were removed from pmxi_posts table when activating WPAI on multisite installation</li>\r\n 	<li>improvement: git rid of deprecated join query on manage imports screen</li>\r\n 	<li>improvement: add is_update_post_format option</li>\r\n 	<li>improvement: add wp_all_import_manual_matching filter</li>\r\n 	<li>improvement: add wp_all_import_logger filter</li>\r\n 	<li>improvement: add display type option for Product Categories</li>\r\n 	<li>improvement: update scheduling keys in the scheduling service when changed in settings</li>\r\n</ul>\r\n<h4>4.6.5 2020-10-24</h4>\r\n<ul>\r\n 	<li>improvement: added support for custom FTP root paths via filter</li>\r\n 	<li>improvement: return to 1st record in file when applying filters</li>\r\n 	<li>bug fix: update only selected custom fields didn\'t work properly</li>\r\n 	<li>bug fix: update featured image provided by 3rd party add-ons didn\'t work properly</li>\r\n 	<li>bug fix: get rid of unused deprecated function add_contextual_help()</li>\r\n 	<li>bug fix: impossible to move past step 4 when using import template that had import schedules configured</li>\r\n 	<li>bug fix: last run timestamp not updated if import file is valid</li>\r\n 	<li>bug fix: no records available when multiple filters are removed</li>\r\n</ul>\r\n<h4>4.6.4 2020-10-07</h4>\r\n<ul>\r\n 	<li>New Feature: Import files from FTP</li>\r\n 	<li>improvement: deprecate \'High Speed Small File Processing\' import option</li>\r\n 	<li>improvement: allow multiple import IDs to be passed to WP-CLI</li>\r\n 	<li>improvement: sort imports by friendly name</li>\r\n 	<li>improvement: improve import speed when matching WooCommerce products by _sku custom field</li>\r\n 	<li>bug fix: \'Change image file names\' setting used when \'Use images currently in Media Library\' is selected</li>\r\n 	<li>bug fix: existing Reviews content type conflicts with WooCommerce Reviews</li>\r\n 	<li>bug fix: \'Use images currently in Media Library\' option tries to match images in content section</li>\r\n 	<li>bug fix: periods removed from cron job keys when saving plugin settings</li>\r\n 	<li>bug fix: references in \'pmxi_posts\' table for terms imported via \'Taxonomies\' imports removed on plugin deactivation</li>\r\n 	<li>bug fix: invalid images in post content downloaded as HTML pages</li>\r\n 	<li>bug fix: chromium scroll anchoring causes screen jumping effect</li>\r\n 	<li>bug fix: pagenum query argument causes broken link on import complete screen</li>\r\n 	<li>bug fix: WPML translations matching don\'t work for product variations in some cases</li>\r\n 	<li>bug fix: unable to match existing comments/reviews by custom field</li>\r\n 	<li>bug fix: unable to import existing files from sub folders</li>\r\n 	<li>bug fix: disabling \'Keep images currently in Media Library\' invalidates hashes when \'Images\' aren\'t set to be updated</li>\r\n 	<li>bug fix: changing image options in add-ons using Rapid Add-On API doesn\'t invalidate hashes</li>\r\n 	<li>bug fix: post created/updated/deleted counts disappear from \'Import in Progress\' page upon import completion</li>\r\n</ul>\r\n<h4>4.6.3 2020-08-11</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: compatibility with WordPress 5.5</li>\r\n 	<li>bug fix: new log created on each cron processing call</li>\r\n 	<li>API: added helper function wp_all_import_get_import_id()</li>\r\n 	<li>API: added helper function wp_all_import_get_import_post_type($import_id)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n&nbsp;\r\n<h4>4.6.2 2020-07-07</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: Import Comments</li>\r\n 	<li>improvement: Import WooCommerce Reviews</li>\r\n 	<li>improvement: Skip updating records when data in import file has not changed</li>\r\n 	<li>improvement: Optimize speed when matching updated posts by custom field or SKU</li>\r\n 	<li>improvement: Disable scheduled imports via Automatic Scheduling UI</li>\r\n 	<li>API: add post ID to wp_all_import_images_uploads_dir</li>\r\n 	<li>bug fix: CodeMirror throws missing dependencies error</li>\r\n 	<li>bug fix: when using Match Images by URL images are also matched by filename</li>\r\n 	<li>bug fix: CSV column header detection causes issues in some cases</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.6.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: run imports via WP-CLI</li>\r\n 	<li>bug fix: switch to CodeMirror implementation shipped in WordPress core</li>\r\n 	<li>bug fix: unable to double click to insert XPath in some cases</li>\r\n 	<li>bug fix: unable to apply pmxi_is_images_to_update filter to featured images</li>\r\n 	<li>bug fix: unable to match existing images when suffix is added to file name during import</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.6.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>API: add new filter wp_all_import_scan_files_recursively</li>\r\n 	<li>bug fix: import custom fields caused import duplicate values</li>\r\n 	<li>bug fix: unable to match existing scaled images</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.9</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: import post content images from srcset attribute</li>\r\n 	<li>API: add new filter wp_all_import_recount_terms_after_import</li>\r\n 	<li>API: add new filter wp_all_import_content_images_get_full_size</li>\r\n 	<li>API: add new filter wp_all_import_feed_type</li>\r\n 	<li>bug fix: original_value argument for pmxi_custom_field contains incorrect value</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.8</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: match existing images by filename with underscores</li>\r\n 	<li>API: add new action wp_all_import_before_preserve_post_data</li>\r\n 	<li>API: add new filter wp_all_import_specified_delimiters</li>\r\n 	<li>bug fix: attachment author not imported for API image imports</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.7</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: get files nested in subdirectories from /wp-content/uploads/wpallimport/files</li>\r\n 	<li>improvement: add support for importing WebP images</li>\r\n 	<li>bug fix: images in content not being imported when creating new items</li>\r\n 	<li>bug fix: unable to match existing users by user ID</li>\r\n 	<li>bug fix: strip special characters from cron job key</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.6</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: add support for .tsv format</li>\r\n 	<li>improvement: load WP All Import only on admin dashboard on cron calls</li>\r\n 	<li>API: add new action pmxi_before_delete_post</li>\r\n 	<li>API: add new filter wp_all_import_use_wp_set_object_terms</li>\r\n 	<li>API: add new filter wp_all_import_copy_uploaded_file_into_files_folder</li>\r\n 	<li>API: add new filter wp_all_import_is_php_allowed</li>\r\n 	<li>API: add current XML variable to pmxi_article_data filter</li>\r\n 	<li>API: add articleData argument to wp_all_import_images_uploads_dir filter</li>\r\n 	<li>bug fix: search for existing images doesn\'t work properly when rename images option in use</li>\r\n 	<li>bug fix: post terms incorrect after import complete, must be recounted</li>\r\n 	<li>bug fix: empty attachments created when attachment import fails</li>\r\n 	<li>bug fix: page template for some posts is overwritten in some cases</li>\r\n 	<li>bug fix: pmxi_update_post_meta action not firing in some cases</li>\r\n 	<li>bug fix: unable to import featured image from content section</li>\r\n 	<li>bug fix: matching posts by ID matches and imports into attachments with the same ID</li>\r\n 	<li>bug fix: matching taxonomy terms by term ID matches and imports into posts and attachments with the same ID</li>\r\n 	<li>bug fix: remove deprecated function pmxi_convert_encoding from API</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.5</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: do not keep trigger log items in history</li>\r\n 	<li>improvement: added new filter wp_all_import_search_image_by_wp_attached_file</li>\r\n 	<li>improvement: added new filter wp_all_import_get_existing_image</li>\r\n 	<li>improvement: added pmxi_import_failed action</li>\r\n 	<li>improvement: search for existing attachments in /files folder</li>\r\n 	<li>improvement: set featured image from img tags when importing content</li>\r\n 	<li>bug fix: don\'t delete records from pmxi_posts for existing users and taxonomy terms</li>\r\n 	<li>bug fix: skipping empty lines during csv to xml convertation</li>\r\n 	<li>bug fix: skip post when custom field data is unchanged</li>\r\n 	<li>bug fix: import custom field name via XPath</li>\r\n 	<li>bug fix: trigger delete_post action when imported posts are deleting</li>\r\n 	<li>bug fix: imports that are scheduled to run at 12am/pm</li>\r\n 	<li>bug fix: fixed updating custom fields with quotes</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.4</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>bug fix: import using stream reader</li>\r\n 	<li>bug fix: generation temporary files in system temporary folder</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.3</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: add support for Toolset Types</li>\r\n 	<li>bug fix: trigger deleted_user action when import deleting a user</li>\r\n 	<li>bug fix: add-ons api - searching for existing images in pmxi_images table</li>\r\n 	<li>bug fix: php error on array push alias</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>new feature: Automatic Scheduling - run imports on a schedule</li>\r\n 	<li>improvement: search for existing images based on remote image URL</li>\r\n 	<li>improvement: various backend improvements to image imports</li>\r\n 	<li>improvement: various import speed optimizations</li>\r\n 	<li>bug fix: remove deprecated function calls for PHP 7.2 compatibility</li>\r\n 	<li>bug fix: delete db tables when mu blog deleted</li>\r\n 	<li>bug fix: remove BOM from import templates</li>\r\n 	<li>bug fix: saving CSV delimiter when changing import file</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: import images from dropbox</li>\r\n 	<li>improvement: skips import process to the first specific record</li>\r\n 	<li>improvement: added new filter wp_all_import_is_render_whole_xml_tree</li>\r\n 	<li>improvement: added wp_all_import_images_uploads_dir filter into add-ons api</li>\r\n 	<li>bug fix: conflict with InfiniteWP</li>\r\n 	<li>bug fix: oddity update notification for Link cloaking add-on</li>\r\n 	<li>bug fix: load functions before pmxi_before_xml_import</li>\r\n 	<li>bug fix: do not re-count category terms when post imported as draft</li>\r\n 	<li>bug fix: import base64 encoded images in add-ons</li>\r\n 	<li>bug fix: woo order custom fields auto-detection</li>\r\n 	<li>security fix - XSS exploit (Special thanks to Mardan Muhidin for reporting)</li>\r\n 	<li>security fix - XSS exploit (Special thanks to Yuji Tounai for reporting)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.5.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: Make the WooCo Short Description expandable</li>\r\n 	<li>improvement: show notice when function editor is not saved</li>\r\n 	<li>improvement: added timestamp to import log lines</li>\r\n 	<li>improvement: added support for bmp images</li>\r\n 	<li>improvement: added new action pmxi_before_post_import_{$addon}</li>\r\n 	<li>security fix: patch XSS exploit</li>\r\n 	<li>bug fix: import pages hierarchy</li>\r\n 	<li>bug fix: error in pclzip.lib.php with php 7.1</li>\r\n 	<li>bug fix: import taxonomies hierarchy</li>\r\n 	<li>bug fix: json to xml convertation</li>\r\n 	<li>bug fix: import password protected feeds with port defined</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.9</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: custom fields detection</li>\r\n 	<li>improvement: new action wp_all_import_post_skipped</li>\r\n 	<li>improvement: updated history page title</li>\r\n 	<li>improvement: optimize large imports deletion</li>\r\n 	<li>improvement: added import friendly name to confirm screen</li>\r\n 	<li>improvement: sql query optimization on manage imports screen</li>\r\n 	<li>improvement: added wp_all_import_shard_delay filter</li>\r\n 	<li>improvement: added wp_all_import_images_uploads_dir filter</li>\r\n 	<li>bug fix: compatibility with WPML</li>\r\n 	<li>bug fix: generation image filename</li>\r\n 	<li>bug fix: wp_all_import_specified_records filter</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.8</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: added hungarian translation</li>\r\n 	<li>bug fix: csv headers generation</li>\r\n 	<li>bug fix: import template from Import Settings works again</li>\r\n 	<li>bug fix: users no longer logged out when user is update via import</li>\r\n 	<li>bug fix: images with encoded quotes</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.7</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>bug fix: cron job completed early for imports with xpath</li>\r\n 	<li>bug fix: csv headers with non latin characters</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.6</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>bug fix: cron job un-triggered on timeout error</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.5</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>bug fix: import xls from dropbox</li>\r\n 	<li>bug fix: template preview</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.4</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: new filter \'wp_all_import_phpexcel_delimiter\'</li>\r\n 	<li>improvement: new filter \'wp_all_import_is_trim_parsed_data\'</li>\r\n 	<li>improvement: added new \'filter wp_all_import_skip_x_csv_rows\'</li>\r\n 	<li>improvement: added csv delimiter setting to import options screen</li>\r\n 	<li>bug fix: taxonomies dropdown list</li>\r\n 	<li>bug fix: cron job was never untriggered when calling to undefined function</li>\r\n 	<li>bug fix: taxonomies preview</li>\r\n 	<li>bug fix: import duplicate tags</li>\r\n 	<li>bug fix: importing taxonomy terms that already exist in a different taxonomies</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.3</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>bug fix: parsing images for newly added records</li>\r\n 	<li>bug fix: the event calendar conflict</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: added new filter wp_all_import_phpexcel_object to modify excel data before import</li>\r\n 	<li>bug fix: search for images ending with underscores in media</li>\r\n 	<li>bug fix: import hierarchical posts and pages</li>\r\n 	<li>bug fix: import custom post type page templates</li>\r\n 	<li>bug fix: matching taxonomies by name</li>\r\n 	<li>bug fix: custom fields validation</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: compatibility with PHP 7.x</li>\r\n 	<li>improvement: search for existing attachments option</li>\r\n 	<li>improvement: new filter for file path of functions.php file</li>\r\n 	<li>bug fix: images preview</li>\r\n 	<li>bug fix: improved matching for images similar to image.com.png</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.4.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>new feature: added import taxonomies feature</li>\r\n 	<li>bug fix: hierarchy taxonomies preview</li>\r\n 	<li>bug fix: empty logs folder generation</li>\r\n 	<li>bug fix: \'Keep images currently in Media Library\' option for add-ons</li>\r\n 	<li>bug fix: import bundles with gz files</li>\r\n 	<li>bug fix: custom functions for attachments</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.3.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>improvement: \'Force Stream Reader\' setting</li>\r\n 	<li>improvement: tar + gz compression support for remote feeds</li>\r\n 	<li>improvement: new filter \'wp_all_import_auto_create_csv_headers\'</li>\r\n 	<li>improvement: new filter \'wp_all_import_is_base64_images_allowed\'</li>\r\n 	<li>improvement: new filter \'wp_all_import_set_post_terms\' to leave a specific category alone when a post is being updated</li>\r\n 	<li>bug fix: cron import timeout when set missing outofstock option is enabled</li>\r\n 	<li>bug fix: nodes navigation for xpath like /news/item</li>\r\n 	<li>bug fix: frozen import template screen for cyrillic XML feeds</li>\r\n 	<li>bug fix: conflict between taxonomies &amp; user import</li>\r\n 	<li>bug fix: creating users with the same email</li>\r\n 	<li>bug fix: enable keep line breaks option by default</li>\r\n 	<li>bug fix: composer namespace conflict</li>\r\n 	<li>bug fix: images preview when wp is in subdirectory</li>\r\n 	<li>bug fix: \'Instead of deletion, set Custom Field\' option for users import</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.3.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed issue with libxml 2.9.3</li>\r\n 	<li>execute \'pmxi_article_data\' filter for all posts ( new &amp; existing )</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.3.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>added de_CH translation</li>\r\n 	<li>added support for .svg images</li>\r\n 	<li>added possibility for import excerpts for pages</li>\r\n 	<li>added new filter \'wp_all_import_specified_records\'</li>\r\n 	<li>added new filter \'wp_all_import_is_post_to_delete\'</li>\r\n 	<li>fixed saving function editor</li>\r\n 	<li>fixed custom fields mapping rules with \'0\' value</li>\r\n 	<li>fixed termination of the import if the \"Delete source XML file after importing\" is checked</li>\r\n 	<li>disable XMLReader stream filter for HHVM</li>\r\n 	<li>improve search for existing images in media gallery</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.9</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed error messages on step 4</li>\r\n 	<li>fixed renaming image files</li>\r\n 	<li>fixed delete missing records option</li>\r\n 	<li>fixed csv to xml convertation in case when there are some equal titles in csv file</li>\r\n 	<li>stop using $HTTP_RAW_POST_DATA for PHP 7.x compatibility</li>\r\n 	<li>added new action \'pmxi_missing_post\'</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.8</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>update required database tables</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.7</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed detecting root nodes with colons in names</li>\r\n 	<li>fixed php notice \"Undefined variable: existing_meta_keys\"</li>\r\n 	<li>fixed rendering special chars in function editor</li>\r\n 	<li>fixed css for WordPress 4.4</li>\r\n 	<li>added feature to delete only posts not import</li>\r\n 	<li>added feature to download template/bundle from import settings</li>\r\n 	<li>added new option for importing images \"Use images currently in Media Library\"</li>\r\n 	<li>remove periods to hyphens convertation in image name</li>\r\n 	<li>auto detect dropbox URLs and change to dl=1</li>\r\n 	<li>changed comma delimiting behavior/UI in image meta</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.6</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed preview prices</li>\r\n 	<li>fixed counting XML nodes</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.5</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed \'Delete source XML file after importing\' option</li>\r\n 	<li>fixed ‘Instead of deletion, change post status to Draft’ option</li>\r\n 	<li>fixed reading XML files with NS in element names</li>\r\n 	<li>added ‘WooCommerce Order’ to post type list on step 1</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.4</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed duplicate matching by custom field</li>\r\n 	<li>fixed error messages on step1 in case when server throws fatal error e.q. time limit exception</li>\r\n 	<li>fixed option \"Delete posts that are no longer present in your file\", now it works with empty CSV files which has only one header row</li>\r\n 	<li>fixed importing custom fields with the same name</li>\r\n 	<li>fixed custom functions in images preview</li>\r\n 	<li>added es_ES translation</li>\r\n 	<li>added de_DE translation</li>\r\n 	<li>added iterative ajax delete process ( deleting associated posts )</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.3</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>Fixed removing uploaded XML source file on re-run process</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>Fixed saving function editor</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed duplicate matching by custom field ( cron )</li>\r\n 	<li>fixed converting image filenames to lowercase</li>\r\n 	<li>fixed import html to image description</li>\r\n 	<li>fixed import _wp_old_slug</li>\r\n 	<li>added Post ID to manual record matching</li>\r\n 	<li>added \'Comment status\' to \'Choose data to update\' section</li>\r\n 	<li>added \'cancel\' to cron API /wp-cron.php?import_key=Kt&amp;import_id=407&amp;action=cancel</li>\r\n 	<li>added function editor</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.2.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed parsing CSV with empty lines</li>\r\n 	<li>fixed parsing multiple IF statements</li>\r\n 	<li>fixed preview in case when ‘Disable the visual editor when writing’ is enabled</li>\r\n 	<li>fixed conflict with WooCommerce - Store Exporter Deluxe</li>\r\n 	<li>added possibility to start synchronized cron requests &amp;sync=1</li>\r\n 	<li>added notifications for required addons</li>\r\n 	<li>added support for wp all export bundle</li>\r\n 	<li>added support for manual import bundle</li>\r\n 	<li>added feature \'click to download import file\'</li>\r\n 	<li>added validation for excerpt and images sections</li>\r\n 	<li>added auto-detect a broken Unique ID notification</li>\r\n 	<li>added import template notifications</li>\r\n 	<li>removed support for importing WooCommerce Orders</li>\r\n 	<li>changed absolute paths to relative in db</li>\r\n 	<li>updated cron response messages</li>\r\n 	<li>moved uploaded files to \'Use existing\' dropdown</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.7</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>added support for Excel files ( .xls, .xlsx )</li>\r\n 	<li>added new option \'Do not remove images from media gallery\' on import\r\nsettings screen</li>\r\n 	<li>added new options to taxonomies import \'Try to match terms to\r\nexisting child Product Categories\' &amp; \'Only assign Products to the\r\nimported Product Category, not the entire hierarchy\'</li>\r\n 	<li>fixed excessive update requests</li>\r\n 	<li>added options to \'Delete associated posts</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.6</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>load ini_set only on plugins pages</li>\r\n 	<li>fixed saving import template</li>\r\n 	<li>added import post format via XPath</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.5</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed import page template</li>\r\n 	<li>added a second argument to pmxi_saved_post action ( SimpleXML object ) of current record</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.4</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed Apply mapping rules before splitting via separator symbol for manual hierarchy</li>\r\n 	<li>fixed path equal or less than</li>\r\n 	<li>fixed changing unique key when moving back from confirm screen</li>\r\n 	<li>fixed override page template</li>\r\n 	<li>fixed unlink images on deleting missing posts</li>\r\n 	<li>updated wp_all_import_is_post_to_update filter with second argument XML node as array</li>\r\n 	<li>updated compatibility with WP All Export</li>\r\n 	<li>added filter <code>wp_all_import_feed_type</code></li>\r\n 	<li>added possibility to use php to calculate URL on first step <code>[add_to_url(\"https://google.com/\")]</code></li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.3</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed un triggering issue on cron jobs for empty files</li>\r\n 	<li>changed updater priority from 10 to 20</li>\r\n 	<li>added post parent option for all hierarchical CPT</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>Important security fixes - additional hardening, prevention of blind SQL injection and reflected XSS attacks</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>critical security fix - stopping non-logged in users from accessing adminInit https://www.wpallimport.com/2015/02/wp-import-4-1-1-mandatory-security-update/</li>\r\n 	<li>added new filter <code>wp_all_import_is_post_to_update</code> to skip needed posts <code>add_filter(\'wp_all_import_is_post_to_update\', \'is_post_to_update\', 10, 1);</code></li>\r\n 	<li>added new option <code>Search for existing attachments to prevent duplicates in media library<code></code></code></li>\r\n 	<li>fixed imports pagination</li>\r\n 	<li>fixed preview taxonomies</li>\r\n 	<li>fixed upload folder creation when \'upload_dir\' filter defined</li>\r\n 	<li>fixed db schema for wpmu when new site added</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.1.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed cron execution when titles are not defined</li>\r\n 	<li>added an option to separate hierarchy groups via symbol</li>\r\n 	<li>added separator symbol for manually nested taxonomies</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.9</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>added license key setting for automatic update</li>\r\n 	<li>added option <code>search images through attachments</code></li>\r\n 	<li>added option <code>assign term to the bottom level term in the hierarchy</code></li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.8</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed taxonomies preview</li>\r\n 	<li>fixed import meta description for images</li>\r\n 	<li>added feature to assign posts to needed terms</li>\r\n 	<li>added new option for taxonomies <code>Apply mapping rules before splitting via separator symbol</code></li>\r\n 	<li>added set with XPath option for comment status, ping status, page parent, page template</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.7</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed feed detection for rss chanels</li>\r\n 	<li>fixed parsing json data</li>\r\n 	<li>fixed add only new images option</li>\r\n 	<li>fixed delete missing records option</li>\r\n 	<li>added ability to import custom fields with the same name</li>\r\n 	<li>added port setting</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.6</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed encoding for taxonomies mapping</li>\r\n 	<li>optimization for delete missing records option</li>\r\n 	<li>fixed feed type auto-detection</li>\r\n 	<li>fixed changes that related to _wp_page_template meta data</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.5</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed template parsing when php function arguments contains an array()</li>\r\n 	<li>fixed error msg when feed is html page e.g. page 404</li>\r\n 	<li>fixed xpath building</li>\r\n 	<li>update hierarchy taxonomies options</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.4</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>changed main file name to wp-all-import-pro.php</li>\r\n 	<li>fixed feed type auto-detection</li>\r\n 	<li>fixed bug with empty unique keys</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.3</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed re-count record when a file has been changed at an import setting screen</li>\r\n 	<li>fixed database schema auto-update</li>\r\n 	<li>fixed uploading large files</li>\r\n 	<li>fixed auto-detecting root element</li>\r\n 	<li>fixed log storage in database</li>\r\n 	<li>fixed cron execution when \"do not create new records\" option is enabled</li>\r\n 	<li>fixed feed type detection</li>\r\n 	<li>fixed unlink attachment source when posts updated/deleted</li>\r\n 	<li>fixed specialchars in taxnomies/categories mapping</li>\r\n 	<li>updated taxonomies hierarchy settings</li>\r\n 	<li>added a limit 10 to the existing meta values</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>4.0.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>speed up the import of taxonomies/categories</li>\r\n 	<li>added taxonomies/categories mapping feature</li>\r\n 	<li>added custom fields auto-detection feature</li>\r\n 	<li>added custom fields mapping feature</li>\r\n 	<li>added images/taxonomies preview feature</li>\r\n 	<li>added unofficial support for more file formats - json &amp; sql</li>\r\n 	<li>added new setting (secure mode) to protect your files</li>\r\n 	<li>better import logs</li>\r\n 	<li>updated design</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.4.2</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed navigation bug</li>\r\n 	<li>fixed search duplicates</li>\r\n 	<li>fixed duplicate categories</li>\r\n 	<li>fixed path builder for element attributes</li>\r\n 	<li>fixed cron processing for already uploaded files (XML)</li>\r\n 	<li>added taxonomies for pages</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.4.1</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed <code>pmxi_delete_post</code> action: this action was executed after posts were deleted</li>\r\n 	<li>fixed import menu order &amp; post parent for pages</li>\r\n 	<li>fixed import log for continue import feature</li>\r\n 	<li>added is update author option</li>\r\n 	<li>fixed post formats</li>\r\n 	<li>fixed cron processing: WP_Error object was not initialized</li>\r\n 	<li>fixed cron processing for import where XPath filtering is defined</li>\r\n 	<li>fixed UTC dates on manage imports page</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.4.0</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed: import empty content</li>\r\n 	<li>fixed: log files</li>\r\n 	<li>fixed: detect image extension</li>\r\n 	<li>fixed: terms hierarchy on cron job execution</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.3.9</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>added: feature to do not escape shortcodes</li>\r\n 	<li>fixed: pre-processing logic</li>\r\n 	<li>fixed: downloading images with unicode url</li>\r\n 	<li>fixed: clear non ASCII/invalid symbols in CSV files</li>\r\n 	<li>fixed: import option \'Instead of using original image file name, set file name(s)\'</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.3.8</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed: admin notices</li>\r\n 	<li>fixed: creation duplicates draft post via cron</li>\r\n 	<li>fixed: images with encoded symbols</li>\r\n 	<li>fixed: upload file via URL</li>\r\n 	<li>fixed: php notices</li>\r\n 	<li>added: compatibility with WP 3.9</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.3.7</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>updated convertation CSV to XML with XMLWriter</li>\r\n 	<li>fixed import *.zip files</li>\r\n 	<li>fixed xpath helper on step 2</li>\r\n 	<li>fixed showing zeros in XML tree</li>\r\n 	<li>allow post content to be empty on step 3</li>\r\n 	<li>added autodetect session mode</li>\r\n 	<li>delete deprecated settings <code>my csv contain html code</code> and <code>case sensitivity</code></li>\r\n 	<li>fixed deleting history files</li>\r\n 	<li>fixed autodetect image extensions</li>\r\n 	<li>fixed increasing SQL query length</li>\r\n 	<li>added error messages</li>\r\n 	<li>fixed \"High Speed Small File Processing\" option</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.3.6</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed: multiple cron execution</li>\r\n 	<li>fixed: load options template</li>\r\n 	<li>fixed: session initialization</li>\r\n 	<li>fixed: import search</li>\r\n 	<li>fixed: attachment author on cron execution</li>\r\n 	<li>fixed: download images option</li>\r\n 	<li>added: errors messages to the log</li>\r\n 	<li>added: \"not contains\" filter to step 2</li>\r\n 	<li>added: compatibility with categories mapping addon</li>\r\n 	<li>updated: cpt navigation on step 4</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<h4>3.3.5</h4>\r\n<ul>\r\n 	<li style=\"list-style-type: none;\">\r\n<ul>\r\n 	<li>fixed bug with cron processing</li>\r\n 	<li>fixed bug with saving wrong image name</li>\r\n 	<li>added serialized custom fields feature</li>\r\n 	<li>added compatibility with user import add-on</li>\r\n 	<li>added compatibility with 3rd party developers</li>\r\n 	<li>added new setting \'Cron processing time limit\'</li>\r\n</ul>\r\n</li>\r\n</ul>\";}s:7:\"banners\";a:2:{s:4:\"high\";s:56:\"https://ps.w.org/wp-all-import/assets/banner-772x250.png\";s:3:\"low\";s:0:\"\";}s:18:\"custom_update_note\";s:0:\"\";s:19:\"update_note_version\";s:0:\"\";s:5:\"icons\";a:0:{}s:3:\"msg\";s:33:\"No license key has been provided.\";s:6:\"tested\";s:5:\"6.9.4\";s:6:\"author\";s:6:\"Soflyy\";s:8:\"requires\";s:3:\"5.0\";s:12:\"requires_php\";s:3:\"7.4\";s:12:\"contributors\";a:2:{s:6:\"soflyy\";a:3:{s:12:\"display_name\";s:6:\"soflyy\";s:7:\"profile\";s:37:\"https://profiles.wordpress.org/soflyy\";s:6:\"avatar\";s:51:\"https://wordpress.org/grav-redirect.php?user=soflyy\";}s:11:\"wpallimport\";a:3:{s:12:\"display_name\";s:11:\"wpallimport\";s:7:\"profile\";s:42:\"https://profiles.wordpress.org/wpallimport\";s:6:\"avatar\";s:56:\"https://wordpress.org/grav-redirect.php?user=wpallimport\";}}}','no');
INSERT INTO `wp_options` VALUES ('2123','wp-all-import-pro_timeout_85b8495febade7a221f67b0bca7d59d9','1778878054','yes');
INSERT INTO `wp_options` VALUES ('2127','theme_mods_varner-equipment-theme-v23-lite','a:4:{i:0;b:0;s:18:\"nav_menu_locations\";a:0:{}s:18:\"custom_css_post_id\";i:-1;s:16:\"sidebars_widgets\";a:2:{s:4:\"time\";i:1778874797;s:4:\"data\";a:1:{s:19:\"wp_inactive_widgets\";a:5:{i:0;s:7:\"block-2\";i:1;s:7:\"block-3\";i:2;s:7:\"block-4\";i:3;s:7:\"block-5\";i:4;s:7:\"block-6\";}}}}','off');
INSERT INTO `wp_options` VALUES ('2130','wp-all-export-pro_f3e07d8a5567b52eda97b45478a42948','O:8:\"stdClass\":19:{s:11:\"new_version\";s:6:\"1.9.15\";s:14:\"stable_version\";s:6:\"1.9.15\";s:4:\"name\";s:13:\"WP All Export\";s:4:\"slug\";s:17:\"wp-all-export-pro\";s:6:\"plugin\";s:39:\"wp-all-export-pro/wp-all-export-pro.php\";s:3:\"url\";s:68:\"https://www.wpallimport.com/downloads/wp-all-export-pro/?changelog=1\";s:12:\"last_updated\";s:19:\"2025-12-11 18:02:09\";s:8:\"homepage\";s:56:\"https://www.wpallimport.com/downloads/wp-all-export-pro/\";s:8:\"sections\";a:2:{s:11:\"description\";s:164:\"<p>Learn more about WP All Export at <a href=\"http://www.wpallimport.com/export\" target=\"_blank\" rel=\"noopener noreferrer\">http://www.wpallimport.com/export</a></p>\";s:9:\"changelog\";s:43650:\"<h4>1.9.15</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: IE deprecation notice in WP 6.9</li>\r\n</ul><h4>1.9.14</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: UI updates</li>\r\n</ul><h4>1.9.13</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: scheduling modal shows wrong license status</li>\r\n<li>bug fix: restore missing ACF field sanitize method</li>\r\n</ul><h4>1.9.12</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>fix: add missing placeholder for Latvian translation</li>\r\n<li>improvement: better handling of corrupt/unexpected data when exporting</li>\r\n<li>improvement: update PhpSpreadsheet</li>\r\n</ul><h4>1.9.11</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: add support for exporting WooCommerce Guest Customers when using the User Export Add-On</li>\r\n</ul><h4>1.9.10</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: add partner discounts</li>\r\n<li>bug fix: resolve textdomain notices</li>\r\n</ul><h4>1.9.8</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security improvement: migrate from PHPExcel to PhpSpreadsheet</li>\r\n<li>improvement: UI updates</li>\r\n</ul><h4>1.9.7</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>integration: support sending Function Editor code to WPCodeBox</li>\r\n</ul><h4>1.9.6</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: failed opening required file</li>\r\n</ul><h4>1.9.5</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: UI updates</li>\r\n<li>bug fix: exception when using custom functions in rare cases</li>\r\n<li>bug fix: option to only export users once fails</li>\r\n<li>bug fix: cannot run updates in WP-CLI</li>\r\n<li>bug fix: option to only export orders once not working in some cases</li>\r\n<li>bug fix: CPT export with \'order_id\' meta field can conflict with WooCommerce Order processing code during export in some cases</li>\r\n</ul><h4>1.9.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: UI updates</li>\r\n<li>bug fix: fatal error when exporting orders using \'Only export Orders once\' in some cases</li>\r\n</ul><h4>1.9.3</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: UI issue when using real time exports</li>\r\n<li>bug fix: Scheduling license validation fails in some cases</li>\r\n</ul><h4>1.9.2</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>security improvement, fixes: CVE-2024-7425, CVE-2024-7419</li>\r\n<li>improvement: add filter to enable including internal order meta in Custom Fields list</li>\r\n<li>improvement: add filter to enable alternative \'is_writable\' checks</li>\r\n<li>improvement: optimize queries for option to only export new stuff</li>\r\n<li>improvement: add setting to remove empty CSV columns</li>\r\n<li>API: new filter \'pmxe_use_alternative_is_writable_check\'</li>\r\n<li>API: new filter \'pmxe_show_internal_order_meta_hpos\'</li>\r\n<li>bug fix: do not try to autoload non-wpae classes</li>\r\n<li>bug fix: invalid query when filtering on multiple product fields in an order export</li>\r\n<li>bug fix: Gravity Forms - only trigger real time export if entry is added to form configured for export</li>\r\n<li>bug fix: ignore brackets within strings when validating Function Editor code</li>\r\n<li>bug fix: WP_Query product taxonomies only show on reload</li>\r\n<li>bug fix: incorrect taxonomies showing for WP_Query product exports</li>\r\n<li>bug fix: fatal error when exporting products with WP_Query in some cases</li>\r\n<li>bug fix: ACF section doesn\'t render for Order exports</li>\r\n<li>bug fix: JS error when attempting to dismiss notice</li>\r\n<li>bug fix: function editor parenthesis in strings can lead to validation failures</li>\r\n<li>bug fix: function editor too many redirects and code not saved</li>\r\n</ul><h4>1.9.1</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: \'class not found\' error in some cases</li>\r\n</ul><h4>1.9.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: add support for ‘Migrate’ and bulk edit for new add-on API</li>\r\n<li>bug fix: PHP warning when WooCommerce Export Add-On isn\'t installed</li>\r\n<li>bug fix: some filters do not work with HPOS WooCommerce orders</li>\r\n<li>bug fix: notices when retrieving some WooCommerce order meta fields</li>\r\n<li>bug fix: SQL errors in some cases when using RTE with filters</li>\r\n<li>bug fix: term meta doesn\'t show when editing export template</li>\r\n<li>bug fix: HPOS orders are not detected with the free order export add-on</li>\r\n<li>bug fix: identify post type when using WP_Query export</li>\r\n<li>bug fix: restore compatibility with free order export add-on</li>\r\n<li>bug fix: Gravity Forms RTE exports include all records</li>\r\n</ul><h4>1.8.9</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: require the \'setup_network\' meta capability for access</li>\r\n<li>bug fix: order meta not included when only stored in HPOS tables</li>\r\n<li>bug fix: real time exports don\'t run for records imported via a cron import</li>\r\n<li>bug fix: PHP notice breaking Automatic Scheduling calls when display errors is enabled</li>\r\n<li>bug fix: generate a valid tab delimited file for GMC exports</li>\r\n<li>	bug fix: manage exports page not honoring date and time formats set in WordPress</li>\r\n<li>bug fix: do not remove HTML markup from GMC description field</li>\r\n<li>bug fix: only one order item is exported in custom XML exports when HPOS is enabled</li>\r\n<li>bug fix: the export file is sometimes deleted after export when WP All Import is active</li>\r\n<li>bug fix: all orders are exported when using real time exports with HPOS only</li>\r\n<li>bug fix: new Add-On API field sections not showing for Order exports (requires WooCommerce Export Add-On version 1.0.10 beta 1.4+)</li>\r\n<li>bug fix: only retrieve shop_order record type from HPOS</li>\r\n<li>bug fix: fatal error when exporting WooCommerce Customers</li>\r\n<li>bug fix: license key is jumbled if AUTH_SALT changes</li>\r\n<li>bug fix: fatal error if HPOS enabled and no valid order found when exporting order meta</li>\r\n<li>bug  fix: deprecation notice when running user exports</li>\r\n<li>bug fix: add missing parameter to PMXE_Admin_Export class</li>\r\n<li>bug fix: parse error when using custom functions with certain values</li>\r\n<li>bug fix: fatal error when saving exports in some cases</li>\r\n</ul><h4>1.8.8</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: restore compatibility with PHP 7.4</li>\r\n<li>bug fix: Gravity Forms add-on exporting HTML encoded values</li>\r\n</ul><h4>1.8.7</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>API: first version of new add-on API</li>\r\n<li>bug fix: GMC height and width fields incorrectly calculated in some cases</li>\r\n<li>bug fix: client mode options do not appear in some cases</li>\r\n<li>bug fix: ‘count’ fatal error in WP_Comment_Query exports</li>\r\n<li>bug fix: WooCommerce Product post meta not correctly retrieved with HPOS active</li>\r\n<li>improvement: better GMC Next support</li>\r\n<li>improvement: increase accuracy of Scheduling service connection checks</li>\r\n</ul><h4>1.8.6</h4>\r\nMinimum WordPress version: 5.0\r\nMinimum PHP version: 7.4\r\n<ul>\r\n<li>security improvement</li>\r\n<li>API: add new filter \'wp_all_export_functions_file_path\' to change the Function Editor\'s file location</li>\r\n<li>API: add new filter \'wp_all_export_product_variation_where\' to override the WP_Query \'where\' for variations</li>\r\n<li>API: add new filter \'wp_all_export_meta_query_limit\' to control how many custom fields can be shown</li>\r\n<li>bug fix: resolve PHP notices for ajax requests</li>\r\n<li>bug fix: fatal error on pre-HPOS WooCommerce versions</li>\r\n<li>bug fix: fatal error in some cases when exporting to XML or GMC</li>\r\n<li>bug fix: fatal error when retrieving file if export doesn\'t exist</li>\r\n<li>bug fix: PHP 8.2 errors</li>\r\n<li>improvement: better handling of brackets in exported data when using custom export fields</li><h4>1.8.5</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.2</li>\r\n<li>note: WooCommerce Export Add-On 1.0.8+ is required to export orders</li>\r\n<li>improvement: better PHP 8.2 support</li>\r\n<li>improvement: add support for filtering by parent slug</li>\r\n<li>improvement: enable adding BOM to files by default for new exports and improve description</li>\r\n<li>improvement: minimize code called during AJAX requests</li>\r\n<li>improvement: remove \'wp_navigation\' from dropdown on Step 1</li>\r\n<li>improvement: gracefully handle cron URL calls to nonexistent exports</li>\r\n<li>improvement: add \'cancel\' action for cron URLs</li>\r\n<li>improvement: only add code to \'admin_head\' when on WP All Export pages</li>\r\n<li>bug fix: resolve miscellaneous PHP notices</li>\r\n<li>bug fix: setting \'Display each product in its own row\' not saved in some cases</li>\r\n<li>bug fix: prevent saved WP All Export sessions from being corrupted by some database configurations</li>\r\n</ul><h4>1.8.4</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.2</li>\r\n<li> improvement: prevent caching of file URLs used with Zapier</li>\r\n<li> adjustment: uncheck \'Display each product in its own row ?\' by default when using \'Migrate\' option for WooCommerce Orders</li>\r\n<li> bug fix: corrected XML layout when using real time order exports</li>\r\n<li> bug fix: corrected exporting of comment IDs to XLS</li>\r\n<li> bug fix: ensure the correct Unique Identifier is set when using the \'Import with WP All Import\' option</li>\r\n</ul><h4>1.8.3</h4><ul>\r\n<li>bug fix: resolve \'enable_real_time_exports\' notice</li>\r\n<li>bug fix: fatal error when post types are defined using closures</li>\r\n</ul><h4>1.8.2</h4><ul>\r\n<li>improvement: individual record data is now available in Zapier when using real time exports (requires 2.0.1+ Zapier trigger version)</li>\r\n<li>improvement: allow exporting \'0\' value in ACF fields</li>\r\n<li>improvement: better \'s\' parameter support for WP_Query exports</li>\r\n<li>improvement: clean up PHP 8 related notices</li>\r\n<li>improvement: better support for symlinked /upload folders</li>\r\n<li>improvement: remove deprecated jQuery functions</li>\r\n<li>improvement: enhanced real time exporting support for RealHomes theme properties</li>\r\n<li>bug fix: don\'t change the \'Product\' label used in the ShopCommerce theme\'s breadcrumbs</li>\r\n<li>bug fix: resolve PHP notices related to Google Merchant Center exports</li>\r\n<li>bug fix: prevent custom XML editor from being shown when exporting to CSV in rare circumstances</li>\r\n<li>bug fix: correct Gravity Forms exported record counts</li>\r\n<li>bug fix: delete missing now works properly with imports created with the \'Import with WP All Import\' option</li>\r\n</ul><h4>1.8.1</h4><ul>\r\n<li>new feature: real time exports - <a href=\"https://www.wpallimport.com/documentation/how-to-run-real-time-exports/\" target=\"_blank\">https://www.wpallimport.com/documentation/how-to-run-real-time-exports/</a> </li>\r\n<li>improvement: set headers to prevent cron URLs and export bundle from being cached</li>\r\n<li>bug fix: enable use of \'s\', \'LIKE\' and \'NOT LIKE\' in WP_Query exports</li>\r\n</ul><h4>1.8.0 </h4><ul><li>bug fix: revert filtering improvements</li></ul>\r\n<h4>1.7.9</h4><ul>\r\n<li>security improvement</li>\r\n<li>bug fix: JavaScript error when the user has the \'Disable syntax highlighting when editing code\' option enabled</li>\r\n<li>bug fix: only one export field can use the \'Export the value returned by a PHP function\' option at a time</li>\r\n<li>improvement: restore compatibility for WordPress 5.0+</li>\r\n<li>improvement: better filtering performance</li>\r\n<li>improvement: better \'custom export field\' performance</li>\r\n</ul><h4>1.7.8</h4><ul><li>bug fix: cannot export products in a single language when using WPML</li></ul>\r\n</ul><h4>1.7.7</h4><ul>\r\n<li>new feature: add option to disable generation of empty export files if no records are matched for export when running via automation</li>\r\n<li>bug fix: allow exporting empty value with custom export field</li>\r\n<li>bug fix: encoded ampersand showing in \'Confirm & Run\' text</li>\r\n<li>bug fix: delimiters are sometimes removed when a field with multiple values is used in a custom export field</li>\r\n<li>bug fix: prevent caching of GMC export files</li>\r\n<li>bug fix: properly format multiple values provided via \'Custom data\' for Product Type in a GMC export</li>\r\n<li>improvement: resolve miscellaneous PHP notices</li>\r\n<li>improvement: only check Scheduling Service connectivity if a Scheduling license has been saved</li>\r\n<li>improvement: UI enhancements</li>\r\n<li>improvement: use CodeMirror library from WordPress Core</li>\r\n</ul><h4>1.7.6</h4><ul>\r\n<li>improvement: add support for Country, Region, and Service shipping sub-attributes for GMC exports</li>\r\n<li>bug fix: can\'t save code to Function Editor</li>\r\n<li>bug fix: error when product dimensions are empty in GMC exports</li>\r\n</ul><h4>1.7.5</h4><ul>\r\n<li>improvement: UI updates</li>\r\n</ul><h4>1.7.4</h4>- bug fix: jQuery nestedSortable compatibility with WordPress 5.9\r\n- improvement: PHP 8 compatibility<h4>1.7.3</h4><ul>\r\n<li>New Feature: compatibility with the Gravity Forms Export Add-On</li>\r\n<li>improvement: fallback to PclZip if ZipArchive isn\'t available</li>\r\n<li>improvement: add support for Cyrillic and Greek characters in element names</li>\r\n<li>bugfix: some output not correctly escaped</li>\r\n<li>bugfix: in some cases, export files are cached when downloaded via a direct link</li>\r\n<li>bugfix: error when exporting attributes</li>\r\n<li>bugfix: notice  when saving client mode settings</li>\r\n<li>bugfix: error on PHP 8 when exports are corrupt</li>\r\n<li>bugfix: error when exporting custom field in simple XML</li>\r\n</ul><h4>1.7.2</h4><ul>\r\n<li>improvement: add support for exporting non-WooCommerce \'product\' CPTs</li>\r\n<li>improvement: initial PHP 8 support</li>\r\n<li>bug fix: fatal error when running \'post\' WP_Query export</li>\r\n<li>bug fix: unexpected newline added to manual custom XML exports</li>\r\n<li>bug fix: CPT exports failing when WooCommerce Export Add-On not active</li>\r\n<li>bug fix: Google Merchant Center shipping dimension unit conversions were incorrect in some cases</li>\r\n<li>bug fix</li>\r\n</ul><h4>1.7.1</h4>\r\n<ul>\r\n 	<li>improvement: decrease the frequency of plugin update checks</li>\r\n 	<li>improvement: add HKG Dollar to Google Merchant Center exports</li>\r\n 	<li>bugfix: error when filtering by WPML language</li>\r\n 	<li>bugfix: WPML language filter not applied when running scheduled exports</li>\r\n 	<li>bugfix: closing tag missing when custom XML export files are empty</li>\r\n</ul>\r\n<h4>1.7.0</h4>\r\n<ul>\r\n 	<li>improvement: added RON to Google Merchant Center export currencies</li>\r\n 	<li>improvement: moved ACF and WooCommerce support to add-ons</li>\r\n</ul>\r\n<h4>1.6.7</h4>\r\n<ul>\r\n 	<li>bugfix: XML tag appended to empty CSV files</li>\r\n 	<li>bugfix: ACF user email field not exported correctly</li>\r\n 	<li>bugfix: PHP notice when adjusting prices in Google Merchant Center exports</li>\r\n</ul>\r\n<h4>1.6.6</h4>\r\n<ul>\r\n 	<li>maintenance: compatibility with Elementor v3.3 JavaScript changes</li>\r\n</ul>\r\n<h4>1.6.5</h4>\r\n<ul>\r\n 	<li>improvement: hide _oembed_ fields from custom fields</li>\r\n 	<li>improvement: update scheduling keys in the scheduling service when changed in settings</li>\r\n 	<li>bugfix: filtering by a custom field called featured working only for products</li>\r\n 	<li>bugfix: functions with empty string arguments not parsed correctly in Custom XML exports</li>\r\n 	<li>bugfix: ratings and star count not exported in WooCommerce Review exports</li>\r\n 	<li>bugfix: simple XML exports generate invalid XML when there are no records by missing the closing tag</li>\r\n 	<li>bugfix: values that contain square brackets not exported in Google Merchants Exports</li>\r\n 	<li>bugfix: custom functions not correctly parsed in Google Merchants Exports</li>\r\n 	<li>bugfix: ACF repeater fields are exported using commas as a delimiter, but the bundle defaults to pipes when importing</li>\r\n</ul>\r\n<h4>1.6.4</h4>\r\n<ul>\r\n 	<li>improvement - remove Friendly Name editing option from Client Mode</li>\r\n 	<li>bugfix - array_intersect_key error when PMXE_Options are corrupt</li>\r\n 	<li>bugfix - order item fields with HTML encoded names can\'t be exported</li>\r\n</ul>\r\n<h4>1.6.3</h4>\r\n<ul>\r\n 	<li>New Feature: Allow non-admins to run exports with Client Mode</li>\r\n 	<li>bug fix: incorrect number of processed entries when exporting items only once in multiple iterations</li>\r\n 	<li>bug fix: Google Merchant Center throws error on shipping length</li>\r\n 	<li>bug fix: state not saved for \'Fill in empty columns\' and \'Display each repeater row in its own csv line\' in ACF repeater fields</li>\r\n 	<li>bug fix: js error when removing filters</li>\r\n 	<li>bug fix: use wp_salt() when AUTH_SALT isn\'t defined</li>\r\n 	<li>bug fix: downloadable files aren\'t migrated properly in some cases</li>\r\n 	<li>bug fix: \'0\' is present in the \'Export the value returned by a PHP function\' setting for Attachment fields</li>\r\n 	<li>bug fix: import template in bundle file not set to choose \'WooCommerce Reviews\' when imported</li>\r\n 	<li>bug fix: featured and attached images options not working for image fields</li>\r\n</ul>\r\n<h4>1.6.2</h4>\r\n<ul>\r\n 	<li>bugfix: some checkbox options broken after WordPress v5.5 compatibility fix</li>\r\n</ul>\r\n<h4>1.6.1</h4>\r\n<ul>\r\n 	<li>maintenance: compatibility with WordPress v5.5 jQuery changes</li>\r\n</ul>\r\n<h4>1.6.0</h4>\r\n<ul>\r\n 	<li>improvement: Export WooCommerce Reviews</li>\r\n 	<li>improvement: Migrate Comments and WooCommerce Reviews</li>\r\n 	<li>improvement: Export Cost of Goods Sold to Google Merchant Center</li>\r\n 	<li>improvement: Add WP_Query support for Toolset Types exports</li>\r\n 	<li>bug fix: time not exported in fields with date and time</li>\r\n 	<li>bug fix: date filters with ‘equal or older than’ doesn\'t include dates equal to the filter value</li>\r\n 	<li>bug fix: no default value for \"Set to false if product has no GTIN or MPN\"</li>\r\n 	<li>bug fix: PHP 7.3 warnings when exporting Excel files</li>\r\n</ul>\r\n<h4>1.5.11</h4>\r\n<ul>\r\n 	<li>improvement: export custom ACF fields defined in Gutenberg blocks</li>\r\n 	<li>improvement: disable scheduled exports via Automatic Scheduling UI</li>\r\n 	<li>API: add new filter wp_all_export_no_cache to avoid server cache for export files</li>\r\n 	<li>bug fix: WPAE UI is translated to the filtered WPML language</li>\r\n 	<li>bug fix: custom functions unavailable when editing an exported field</li>\r\n 	<li>bug fix: unable to update filters on the Run Export page</li>\r\n 	<li>bug fix: date filters including first/last day of month do not work properly</li>\r\n 	<li>bug fix: notices related to Google Merchants exports</li>\r\n 	<li>bug fix: exports sent to Zapier in the incorrect order</li>\r\n 	<li>bug fix: WooCommerce customer exports do not correctly report the number of exported customers</li>\r\n 	<li>bug fix: unable to only export customers once via scheduled exports</li>\r\n 	<li>bug fix: fields containing commas incorrectly exported to Google Merchant Center</li>\r\n 	<li>bug fix: product names are incorrectly urlencoded in custom XML exports</li>\r\n 	<li>bug fix: taxonomy meta fields not available for export</li>\r\n 	<li>bug fix: 0 values are represented as an empty string in custom XML exports</li>\r\n 	<li>bug fix: order items doubled in custom export fields in custom XML exports</li>\r\n 	<li>bug fix: custom fields not parsed correctly in custom XML exports</li>\r\n 	<li>bug fix: Manual Scheduling disabled when Automatic Scheduling is selected</li>\r\n 	<li>bug fix: unable to filtering by hours or minutes in some cases</li>\r\n 	<li>bug fix: unable to export ACF group fields</li>\r\n 	<li>bug fix: trying to delete History File fails ungracefully if it doesn\'t exist</li>\r\n 	<li>bug fix: Fee Amount exporting as an empty field in custom XML exports</li>\r\n</ul>\r\n<h4>1.5.10</h4>\r\n<ul>\r\n 	<li>improvement: add SAR currency to Google Merchant Center</li>\r\n 	<li>improvement: add default Unit Pricing Measure to Google Merchant Center</li>\r\n 	<li>improvement: only update max_execution_time on plugin requests, don\'t modify it globally</li>\r\n 	<li>bugfix: unable to export WooCommerce customers to XML</li>\r\n 	<li>bugfix: error with empty strings at the beginning or end of function calls</li>\r\n 	<li>bugfix: ACF date field not parsed correctly with some custom date formats</li>\r\n 	<li>bugfix: unable to export image galleries inside ACF flexible content fields to XML</li>\r\n 	<li>bugfix: time-based export filters should use GMT not server time</li>\r\n</ul>\r\n<h4>1.5.9</h4>\r\n<ul>\r\n 	<li>bug fix: unable to export users</li>\r\n</ul>\r\n<h4>1.5.8</h4>\r\n<ul>\r\n 	<li>improvement: add UAH currency to Google Merchant Center exports</li>\r\n 	<li>API: add \'pmxe_is_bundle\' filter</li>\r\n 	<li>bug fix: unable to filter by user data</li>\r\n 	<li>bug fix: wp_query missing error in some cases</li>\r\n 	<li>bug fix: ACF link export incorrectly formatted</li>\r\n 	<li>bug fix: \"Tax Amount\" rounded to nearest integer</li>\r\n 	<li>bug fix: currency included in price field when price is empty for Google Merchant Center exports</li>\r\n</ul>\r\n<h4>1.5.7</h4>\r\n<ul>\r\n 	<li>improvement: add Thai Baht to Google Merchant Center currencies</li>\r\n 	<li>improvement: add custom line endings for CSV</li>\r\n 	<li>API: add new action pmxe_acf_date_picker_format to set custom ACF date formats</li>\r\n 	<li>bugfix: unable to use wp-cron for scheduled exports on sites running PHP-FPM and WordPress 5.1+</li>\r\n 	<li>switched to wp-load for cron URLs, with backwards compatibility for wp-cron</li>\r\n 	<li>bugfix: ACF repeaters export incorrect values in ACF version 5.7.10+</li>\r\n 	<li>bugfix: Google Merchant Center incorrectly converts units from inches to mm</li>\r\n 	<li>bugfix: ACF date format not parsed correctly</li>\r\n 	<li>bugfix: tax amount incorrectly calculated in PHP 7.1+</li>\r\n 	<li>bugfix: is_empty field only looks for NULL fields, not empty values</li>\r\n 	<li>bugfix: exporting ACF user fields results in error</li>\r\n</ul>\r\n<h4>1.5.6</h4>\r\n<ul>\r\n 	<li>add-on: move all user export functionality to new user export add-on</li>\r\n 	<li>improvement: preserve admin body classes that are added by other plugins</li>\r\n 	<li>improvement: change scheduling endpoints from wp-cron.php to wp-load.php for WordPress 5.1/PHP-FPM compatibility</li>\r\n 	<li>bugfix: change language code alias for WPML compatibility</li>\r\n 	<li>bugfix: meta keys that are not returned as an array are exported as empty</li>\r\n 	<li>bugfix: allow uppercase ID in custom XML template</li>\r\n 	<li>bugfix: use ACF date format for date pickers</li>\r\n 	<li>bugfix: custom export field notices not working for WooCommerce orders</li>\r\n 	<li>bugfix: missing items in combine multiple fields are not replaced</li>\r\n 	<li>bugfix: term ID missing when using custom fields and exporting taxonomies</li>\r\n 	<li>bugfix: some WooCommerce attributes cause errors when writing to CSV</li>\r\n 	<li>bugfix: scheduling API responses improperly translated</li>\r\n 	<li>bugfix: changes to field not rendered in preview from edit field modal</li>\r\n</ul>\r\n<h4>1.5.5</h4>\r\n<ul>\r\n 	<li>bug fix: compatibility with ACF v5.7.11</li>\r\n</ul>\r\n<h4>1.5.4</h4>\r\n<ul>\r\n 	<li>improvement: add RTL support for Excel</li>\r\n 	<li>improvement: add Indonesian Rupiah to Google Merchant Center</li>\r\n 	<li>improvement: add Google Merchant Center field name as global variable to be used in custom functions</li>\r\n 	<li>bugfix: improve support for quotes in custom xml</li>\r\n 	<li>bugfix: increase number of rendered categories for Google Merchant Center</li>\r\n 	<li>bugfix: Google Merchant Center dimensions</li>\r\n 	<li>bugfix: include variations when filtering by categories</li>\r\n 	<li>bugfix: combine error messages when exporting refunds</li>\r\n 	<li>bugfix: refund ID snippet not being replaced when field is missing</li>\r\n 	<li>bugfix: fix filtering error when exporting comments</li>\r\n 	<li>bugfix: support exports scheduled at 12am and 12pm</li>\r\n 	<li>bugfix: fix filtering products with titles that contain slashes</li>\r\n 	<li>bugfix: merge headers for empty columns at end of file</li>\r\n 	<li>bugfix: fix filtering UI for long titles</li>\r\n 	<li>bugfix: allow exporting ACF checkbox fields</li>\r\n 	<li>bugfix: pmxe_woo_field parameters incorrect</li>\r\n 	<li>bugfix: downloadable files in custom XML not exporting</li>\r\n 	<li>bugfix: close incorrect tags when exporting ACF</li>\r\n 	<li>bugfix: export serialized values in combined fields</li>\r\n 	<li>bugfix: custom functions in Google Merchant Center price elements not triggering</li>\r\n 	<li>bugfix: get_site_url in multisite when using Google Merchant Center</li>\r\n 	<li>bugfix: allow users to be filtered by name</li>\r\n 	<li>bugfix: fix custom export fields in simple XML exports</li>\r\n 	<li>bugfix: fix tax rate code exports in custom export fields</li>\r\n</ul>\r\n<h4>1.5.3</h4>\r\n<ul>\r\n 	<li>improvement: improve function parsing in custom export fields</li>\r\n 	<li>improvement: Google Merchant Center titles are limited to 150 characters</li>\r\n 	<li>improvement: increase custom query meta limit</li>\r\n 	<li>new filter: added pmxe_after_iteration action</li>\r\n 	<li>bugfix: remove deprecated function calls for PHP 7.2 compatibility</li>\r\n 	<li>bugfix: address various PHP warnings and notices</li>\r\n 	<li>bugfix: filters for WooCommerce product variations</li>\r\n 	<li>bugfix: graceful failure for non:writable uploads folder</li>\r\n 	<li>bugfix: add warning when exporting WooCommerce orders using Automatic Scheduling</li>\r\n 	<li>bugfix: WooCommerce product variations exported as separate products when adding product attributes to custom export fields</li>\r\n 	<li>bugfix: function editor not rendered until clicked</li>\r\n 	<li>bugfix: small UI and spacing issues</li>\r\n 	<li>bugfix: WooCommerce products don\'t on their own row in order exports when using custom export fields</li>\r\n 	<li>bugfix: prices with more than two decimal places are not exported correctly</li>\r\n 	<li>bugfix: \'Only export orders that have been modified since last export\' doesn\'t work when filtering orders</li>\r\n 	<li>bugfix: exporting empty ACF values shifts rows in CSV exports</li>\r\n 	<li>bugfix: Australia missing from scheduling timezones</li>\r\n 	<li>bugfix: exporting meta in WooCommerce orders</li>\r\n 	<li>bugfix: unable to filter or export WooCommerce product visibility data</li>\r\n 	<li>bugfix: cannot export product type for variable products to Google Merchant Center</li>\r\n 	<li>bugfix: Google Merchant Center exports cannot automatically map sub-categories</li>\r\n</ul>\r\n<h4>1.5.2</h4>\r\n<ul>\r\n 	<li>improvement: Support migrating users &amp; keeping passwords</li>\r\n 	<li>improvement: Add Featured Image to Available Data › Media</li>\r\n 	<li>new filter: wp_all_export_raw_prices - disables price formatting</li>\r\n 	<li>bugfix: Error thrown when uploads folder is not writable</li>\r\n 	<li>bugfix: Preview is broken for date fields</li>\r\n 	<li>bugfix: Product visibility broken for old WooCommerce versions</li>\r\n 	<li>bugfix: Custom Export Field values not saved in some cases</li>\r\n 	<li>bugfix: Headers not matching content when they contain special characters</li>\r\n 	<li>bugfix: Headers not matching content when exporting certain ACF fields</li>\r\n 	<li>bugfix: Loading order for styles optimized to reduce conflicts</li>\r\n 	<li>bugfix: Import templates broken for WooCommerce product attributes</li>\r\n 	<li>bugfix: \'Export Images from Post Content\' option doesn\'t displaying in some cases</li>\r\n 	<li>bugfix: JSON parameters can now be passed through functions in Google Merchant Center exports</li>\r\n 	<li>bugfix: WP Query exports broken for users and comments</li>\r\n 	<li>bugfix: Meta missing when migrating unattached images</li>\r\n 	<li>bugfix: Available Data broken when there\'s more than 500 data elements</li>\r\n 	<li>bugfix: Custom Export Fields are unstable when many are added to the same export</li>\r\n</ul>\r\n<h4>1.5.1</h4>\r\n<ul>\r\n 	<li>bug fix: custom fields are exported as their name</li>\r\n</ul>\r\n<h4>1.5.0</h4>\r\n<ul>\r\n 	<li>new feature: Automatic Scheduling</li>\r\n 	<li>new feature: Custom export fields</li>\r\n 	<li>improvement: licenses hidden in the ui and encoded in the database</li>\r\n 	<li>improvement: improved error reporting for custom functions errors</li>\r\n 	<li>improvement: changed excerpt to short description</li>\r\n 	<li>improvement: better price formatting</li>\r\n 	<li>improvement: better function parsing in Google Merchant Center exports</li>\r\n 	<li>improvement: exclude parent products from Google Merchant Center exports</li>\r\n 	<li>improvement: added CHF to list of supported Google Merchant Center currencies</li>\r\n 	<li>improvement: added support for acf clone field</li>\r\n 	<li>improvement: added security token to cron URLs for improved security</li>\r\n 	<li>improvement: added author information to Available Data</li>\r\n 	<li>improvement: added wp_all_export_order_item filter</li>\r\n 	<li>improvement: added wp_all_export_use_csv_compliant_line_endings filter</li>\r\n 	<li>improvement: added wp_all_export_pre_csv_headers filter</li>\r\n 	<li>improvement: added wp_all_export_repeater_delimiter filter</li>\r\n 	<li>bugfix: PHP notices and warnings</li>\r\n 	<li>bugfix: error when activating Pro version and Free version</li>\r\n 	<li>bugfix: splitting custom XML export files</li>\r\n 	<li>bugfix: removed moment.js which was causing false virus positives in some browsers</li>\r\n 	<li>bugfix: Google Merchant Center category mapping</li>\r\n 	<li>bugfix: do not update comment status by default</li>\r\n 	<li>bugfix: \"only export modified posts\" when using cron</li>\r\n 	<li>bugfix: file name filters when using crons</li>\r\n 	<li>bugfix: shortcodes in custom XML snippets</li>\r\n 	<li>bugfix: ACF flexible fields</li>\r\n 	<li>bugfix: problems when running Google Merchant Center exports via cron</li>\r\n 	<li>bugfix: CSV writer fixes to take into account https://bugs.php.net/bug.php?id=43225</li>\r\n 	<li>bugfix: exporting ACF and custom fields with HTML tags</li>\r\n 	<li>bugfix: stray root tags in WooCommerce Order exports</li>\r\n 	<li>bugfix: timeouts when connecting Jetpack to WordPress.com</li>\r\n 	<li>bugfix: exporting product images in Google Merchant Center</li>\r\n 	<li>bugfix: corrupted Excel files</li>\r\n 	<li>bugfix: conflicts with some plugins changing the post order</li>\r\n 	<li>bugfix: comment handling in custom XML</li>\r\n 	<li>bugfix: blank CodeMirror in dialogs</li>\r\n 	<li>bugfix: parsing CDATA tags that contain HTML tags</li>\r\n 	<li>bugfix: Google Merchant Center handling quotes in functions</li>\r\n 	<li>bugfix: improved Google Merchant Center snippet parser</li>\r\n 	<li>bugfix: CSV headers when field names contained quotes</li>\r\n 	<li>bugfix: included WPML query in variation query</li>\r\n 	<li>bugfix: handling of the \"visibility\" field based on WooCommerce version</li>\r\n</ul>\r\n<h4>1.4.7</h4>\r\n<ul>\r\n 	<li>improvement: Improved accuracy for export timer</li>\r\n 	<li>improvement: Removed moment.js dependency which causes false positives in some antivirus software</li>\r\n 	<li>imporovement New export complete page</li>\r\n 	<li>bugfix: Fixed problems when switching from WPAE free to WPAE pro</li>\r\n 	<li>bugfix: Special characters in product attributes support</li>\r\n 	<li>bugfix: Fix category mapper containing special characters</li>\r\n 	<li>bugfix: Fixed parsing content with shortcodes in custom XML Export</li>\r\n 	<li>bugfix: Fixed exporting ACF fields with no value for some posts</li>\r\n</ul>\r\n<h4>1.4.6</h4>\r\n<ul>\r\n 	<li>improvement: removed autoload=true from wp_options</li>\r\n 	<li>improvement: use \'Export product variations and their parent products\' by default</li>\r\n 	<li>improvement: WPML options in separate section</li>\r\n 	<li>improvement: category mapper optimization</li>\r\n 	<li>improvement: memory usage to avoid memory limit errors</li>\r\n 	<li>bug fix: allow underscores in main xml tags</li>\r\n 	<li>bug fix: prevent uploading import template into wpae</li>\r\n 	<li>bug fix: ID column in CSV</li>\r\n 	<li>bug fix: date equals or older filter</li>\r\n 	<li>bug fix: ACF repeater headers</li>\r\n 	<li>bug fix: size type mapper and no categories message</li>\r\n 	<li>bug fix: export ID in custom XML mode</li>\r\n 	<li>bug fix: date filtering</li>\r\n 	<li>bug fix: export product variation status</li>\r\n 	<li>bug fix: the \"Shipping Class\" field in Google Merchants export.</li>\r\n</ul>\r\n<h4>1.4.5</h4>\r\n<ul>\r\n 	<li>improvement: added new option \'Only export Pages that have been modified since last export\'</li>\r\n 	<li>improvement: added post_modified field</li>\r\n 	<li>improvement: handling functions in google meerchants fields</li>\r\n 	<li>bug fix: snippets parsing in Custom XML Export</li>\r\n 	<li>bug fix: template saving. Fixed product image export to Google Merchants</li>\r\n 	<li>bug fix: export attributes for simple products</li>\r\n 	<li>bug fix: db schema updating</li>\r\n 	<li>bug fix: variations with trashed parents shouldn\'t be included in the export</li>\r\n 	<li>bug fix: google Merchants inconsistent category search</li>\r\n 	<li>bug fix: minified JS to avoid problems for CloudFlare users</li>\r\n</ul>\r\n<h4>1.4.4</h4>\r\n<ul>\r\n 	<li>improvement: export to Google Merchant Center</li>\r\n 	<li>improvement: choose WPML language in export options</li>\r\n 	<li>improvement: filter WooCommerce Orders by order item data</li>\r\n 	<li>improvement: export CSV without header row</li>\r\n 	<li>bug fix: export ACF message field</li>\r\n 	<li>bug fix: export product categories with AFC repeater fields</li>\r\n 	<li>bug fix: export duplicate images from gallery</li>\r\n 	<li>bug fix: filter products by custom fields</li>\r\n 	<li>bug fix: export search</li>\r\n 	<li>bug fix: export product variation attribute names</li>\r\n 	<li>bug fix: processing serialized data in custom snippets</li>\r\n 	<li>bug fix: export more than one coupon_used field</li>\r\n 	<li>bug fix: migrating hierarchical posts and pages</li>\r\n</ul>\r\n<h4>1.4.3</h4>\r\n<ul>\r\n 	<li>improvement: compatibility with PHP 7.x</li>\r\n 	<li>improvement: new export field \'Order Item ID\'</li>\r\n 	<li>improvement: possibility for filter order by order items data</li>\r\n 	<li>improvement: new option \'Include header row and column titles in export\'</li>\r\n 	<li>bug fix: processing serialized data in custom snippets</li>\r\n 	<li>bug fix: export ACF repeater field in custom XML mode</li>\r\n 	<li>bug fix: applying php function to product attributes</li>\r\n 	<li>bug fix: export coupon_used field</li>\r\n</ul>\r\n<h4>1.4.2</h4>\r\n<ul>\r\n 	<li>new feature: added export taxonomies feature</li>\r\n 	<li>improvement: new export variable products options</li>\r\n 	<li>improvement: added possibility to export to xlsx</li>\r\n 	<li>improvement: added ACF fields to \'migrate\' &amp; \'add all fields\' features</li>\r\n 	<li>improvement: added new filter \'wp_all_export_field_name\'</li>\r\n 	<li>improvement: changed default date export to Y/m/d</li>\r\n 	<li>bug fix: export shipping class for product variations</li>\r\n 	<li>bug fix: import template for ACF relationship fields</li>\r\n 	<li>bug fix: export ACF fields in custom XML mode</li>\r\n 	<li>bug fix: export empty images metadata</li>\r\n 	<li>bug fix: import template for ACF gallery</li>\r\n 	<li>bug fix: import template for variation_description</li>\r\n 	<li>bug fix: import template for default product attributes</li>\r\n 	<li>bug fix: fields ordering for custom XML export</li>\r\n 	<li>bug fix: menu order migration</li>\r\n 	<li>bug fix: automatically adding parent_id column on products export</li>\r\n 	<li>bug fix: SQL query ( caused timeout error )</li>\r\n 	<li>bug fix: parsing snippets in attributes in elements</li>\r\n</ul>\r\n<h4>1.4.1</h4>\r\n<ul>\r\n 	<li>bug fix: compatibility with PHP 5.3</li>\r\n</ul>\r\n<h4>1.4.0</h4>\r\n<ul>\r\n 	<li>new feature: export custom xml template</li>\r\n 	<li>improvement: new filter wp_all_export_after_csv_line</li>\r\n 	<li>improvement: date options for sale price dates from/to</li>\r\n 	<li>improvement: ability to use tab as csv delimiter</li>\r\n 	<li>improvement: new filter \'wp_all_export_csv_headers\'</li>\r\n 	<li>improvement: pull the parent taxonomy data when exporting variations</li>\r\n 	<li>improvement: remove spaces from export filename</li>\r\n 	<li>bug fix: \'posts_clauses\' filter issue</li>\r\n 	<li>bug fix: db schema on multisite</li>\r\n 	<li>bug fix: export order items date</li>\r\n 	<li>bug fix: import template for media items</li>\r\n 	<li>bug fix: \'Only export Products once\' for new exports</li>\r\n 	<li>bug fix: export ACF repeater in XML format</li>\r\n 	<li>bug fix: order_completed_date filter</li>\r\n 	<li>bug fix: export in CSV format when \'Main XML Tag\' &amp; \'Record XML Tag\' option are blank</li>\r\n 	<li>bug fix: export order items taxonomies</li>\r\n 	<li>bug fix: export ACF date_time_picker</li>\r\n 	<li>bug fix: date filter by time</li>\r\n 	<li>bug fix: is empty filters</li>\r\n 	<li>bug fix: nested filter rules</li>\r\n</ul>\r\n<h4>1.3.2</h4>\r\n<ul>\r\n 	<li>fixed \'Only export Posts once\' for new exports</li>\r\n 	<li>fixed db schema for multisite</li>\r\n 	<li>fixed export order items date</li>\r\n 	<li>fixed media items export ordering</li>\r\n 	<li>fixed import template for media items</li>\r\n 	<li>fixed export ACF repeater in XML format</li>\r\n 	<li>fixed order_completed_date filter</li>\r\n 	<li>added new filter \'wp_all_export_csv_headers\'</li>\r\n 	<li>added possibility to use tab as csv delimiter \"t\"</li>\r\n 	<li>updated french translation</li>\r\n</ul>\r\n<h4>1.3.1</h4>\r\n<ul>\r\n 	<li>added WooCommerce order migration</li>\r\n 	<li>added _thumbnail_id to the filtering dropdown</li>\r\n 	<li>added new filter \'wp_all_export_is_wrap_value_into_cdata\'</li>\r\n 	<li>added new filters \'wp_all_export_add_before_element\', \'wp_all_export_add_after_element\'</li>\r\n 	<li>added \'WPML Translation ID\' element to available data</li>\r\n 	<li>modified preview to show first 10 records</li>\r\n 	<li>fixed csv export with non comma delimiter</li>\r\n 	<li>fixed conflict with WP Google Maps Pro plugin</li>\r\n 	<li>fixed downloading XLS export file when security mode is disabled</li>\r\n</ul>\r\n<h4>1.3.0</h4>\r\n<ul>\r\n 	<li>fixed misaligned columns on exporting product attributes</li>\r\n 	<li>fixed export nested repeaters field in CSV format</li>\r\n 	<li>fixed conflict between enabled ‘Only export Products once’ &amp; filtering rules</li>\r\n 	<li>fixed live records counting for advanced export mode</li>\r\n 	<li>fixed Events Calendar conflict</li>\r\n 	<li>added Google Merchants support</li>\r\n 	<li>added new filters \'wp_all_export_add_before_node\', \'wp_all_export_add_after_node\'</li>\r\n 	<li>added possibility to filter posts by author data</li>\r\n 	<li>added XLS support, redesign CSV/XML options in Step 2</li>\r\n 	<li>added feature to use php function in filtering rules</li>\r\n 	<li>added possibility export repeater rows one per line</li>\r\n 	<li>added backward compatibility for export comments on WordPress less than 4.2.0</li>\r\n 	<li>exclude orphaned variations from exprt file</li>\r\n 	<li>changed UI for export media data ( images &amp; attachments )</li>\r\n</ul>\r\n<h4>1.2.3</h4>\r\n<ul>\r\n 	<li>fixed export attachment meta alt</li>\r\n 	<li>fixed export manually stored ACF</li>\r\n 	<li>fixed export repeater field for users in csv format</li>\r\n 	<li>fixed saving special chars in function editor</li>\r\n 	<li>fixed import export templates</li>\r\n 	<li>fixed error on activate WPAE license</li>\r\n 	<li>fixed ajaxurl conflict with WPML</li>\r\n 	<li>fixed filtering by ACF taxonomy field</li>\r\n 	<li>create a stable copy of exported file for remote access during export process</li>\r\n 	<li>added French &amp; Latvian translations</li>\r\n 	<li>added \'Variation Description\' field</li>\r\n</ul>\r\n<h4>1.2.2</h4>\r\n<ul>\r\n 	<li>fixed \'wp_all_export_additional_data\' filter on cron job</li>\r\n 	<li>fixed Zapier intergation</li>\r\n 	<li>fixed import template for variable products</li>\r\n 	<li>fixed css for WordPress 4.4</li>\r\n 	<li>fixed export ACF repeater field</li>\r\n</ul>\r\n<h4>1.2.1</h4>\r\n<ul>\r\n 	<li>added export comments</li>\r\n 	<li>added possibility to add NS to field names</li>\r\n 	<li>fixed export repeater field ACF 4.x</li>\r\n 	<li>fixed cron export, was exported wrong data amount when there are sticky posts in database</li>\r\n 	<li>fixed updating filter rules on cron job</li>\r\n 	<li>fixed error on edit custom column name for Woo Orders</li>\r\n</ul>\r\n<h4>1.2.0</h4>\r\n<ul>\r\n 	<li>fixed manage exports screen: \"Info and options\" disappears when WPAI plugin is disabled</li>\r\n 	<li>fixed WP_Query results ordering</li>\r\n 	<li>fixed export ACF repeater field for CSV</li>\r\n 	<li>fixed export filtering</li>\r\n 	<li>added es_ES translation</li>\r\n 	<li>added possibility to change export field name ( related to export WooCommerce Orders )</li>\r\n 	<li>added option \'Split large exports into multiple files\'</li>\r\n 	<li>added option \'Only export posts once\'</li>\r\n 	<li>added option \'Create a new export file each time export is run\'</li>\r\n 	<li>added option \'Fill in empty columns\': If enabled, each order item will appear as its own row with all order info filled in for every column. If disabled, order info will only display on one row with only the order item info displaying in additional rows</li>\r\n 	<li>added ‘pmxe_exported_post’ action: do_action(\'pmxe_exported_post\', $record-&gt;ID );</li>\r\n 	<li>added Zapier support ( beta )</li>\r\n 	<li>added possibility to control main xml tag names &amp; put additional info into xml file: apply_filters(\'wp_all_export_additional_data\', array(), $exportOptions)</li>\r\n 	<li>added export templates</li>\r\n 	<li>added hidden post types to the dropdown list on step 1</li>\r\n 	<li>replaced \'export key\' to \'export hash\' in \'Export File URL\' on scheduling page</li>\r\n 	<li>updated re-run export screen</li>\r\n</ul>\r\n<h4>1.1.1</h4>\r\n<ul>\r\n 	<li>fixed download bundle</li>\r\n 	<li>fixed export repeater fields for ACF 4.x</li>\r\n 	<li>fixed import template for custom product attributes</li>\r\n 	<li>fixed cron job responses, now theay are in JSON format</li>\r\n 	<li>added bundle URL to scheduling page</li>\r\n 	<li>added new option \'include BOM to export file</li>\r\n 	<li>added RU translation</li>\r\n 	<li>added function editor</li>\r\n 	<li>removed hidden post types from dropdown in step 1</li>\r\n</ul>\r\n<h4>1.1.0</h4>\r\n<ul>\r\n 	<li>fixed export taxonomy: name instead of slug</li>\r\n 	<li>fixed export filtering (query with multiple meta keys)</li>\r\n 	<li>fixed display products in own row option</li>\r\n 	<li>fixed pass data through php function</li>\r\n 	<li>added advanced (custom fields) section to export woo orders</li>\r\n 	<li>added draggable element deletion</li>\r\n 	<li>added auto-generate product export fields</li>\r\n 	<li>added \'attributes\' field to product data</li>\r\n 	<li>added feedback page</li>\r\n 	<li>added another \'Auto Generate\' button for products export</li>\r\n 	<li>added button to download bundle for WP All Import</li>\r\n 	<li>updated export file name</li>\r\n 	<li>changed export files destination to /exports</li>\r\n</ul>\r\n<h4>1.0.2</h4>\r\n<ul>\r\n 	<li>Added export users</li>\r\n 	<li>Added scheduled exports</li>\r\n 	<li>Added orders export</li>\r\n 	<li>Added filtering options</li>\r\n</ul>\r\n<h4>1.0.1</h4>\r\n<ul>\r\n 	<li>updated icons</li>\r\n 	<li>fixed taxonomies export</li>\r\n</ul>\r\n<h4>1.0.0</h4>\r\n<ul>\r\n 	<li>Initial release</li>\r\n</ul>\";}s:7:\"banners\";a:2:{s:4:\"high\";s:56:\"https://ps.w.org/wp-all-export/assets/banner-772x250.png\";s:3:\"low\";s:0:\"\";}s:18:\"custom_update_note\";s:0:\"\";s:19:\"update_note_version\";s:0:\"\";s:5:\"icons\";a:0:{}s:3:\"msg\";s:33:\"No license key has been provided.\";s:6:\"tested\";s:5:\"6.9.4\";s:6:\"author\";s:6:\"Soflyy\";s:8:\"requires\";s:3:\"5.0\";s:12:\"requires_php\";s:3:\"7.4\";s:12:\"contributors\";a:2:{s:6:\"soflyy\";a:3:{s:12:\"display_name\";s:6:\"soflyy\";s:7:\"profile\";s:37:\"https://profiles.wordpress.org/soflyy\";s:6:\"avatar\";s:51:\"https://wordpress.org/grav-redirect.php?user=soflyy\";}s:11:\"wpallimport\";a:3:{s:12:\"display_name\";s:11:\"wpallimport\";s:7:\"profile\";s:42:\"https://profiles.wordpress.org/wpallimport\";s:6:\"avatar\";s:56:\"https://wordpress.org/grav-redirect.php?user=wpallimport\";}}}','no');
