INSERT INTO `wp_postmeta` VALUES ('1660','598','description','<h2><strong>Big Tex 10LX Dump Trailer – Heavy-Duty, Hydraulic Lift, Fully Loaded with Features</strong></h2><p><span>Price: $8,560 | Stock #100453</span></p><p><br></p><p><span>The Big Tex 10LX is a premium-grade dump trailer built for contractors, ranchers, landscapers, and anyone who needs dependable hauling power. With 10,000 lbs GVWR, a self-contained hydraulic lift, and reinforced steel construction, this trailer is engineered for serious work. Packed with professional-grade features, it offers superior durability, convenience, and hauling efficiency.</span></p><p><br></p><p><span>Key Features:</span></p><p><span>Axles: (2) 5,200 lb premium cambered axles with quick-lubricating hubs</span></p><p><span>Brakes: Forward self-adjusting electric brakes</span></p><p><span>Suspension: Multi-leaf slipper spring with equalizer</span></p><p><span>Coupler: Adjustable forged 2-5/16\" coupler</span></p><p><span>Safety Chains: 1/4\" Grade 70 with safety latch hooks</span></p><p><span>Jack: 7,000 lb top-wind drop-leg jack</span></p><p><span>Frame: 6\" channel frame</span></p><p><span>Crossmembers: 3\" channel on 16\" centers</span></p><p><span>Floor: 10-gauge smooth steel floor</span></p><p><span>Fenders: 9\" x 72\" diamond plate double square broke</span></p><p><span>Hydraulics:</span></p><p><span>Power up/power down &amp; gravity down hydraulic pump</span></p><p><span>Self-contained single cylinder lift</span></p><p><span>12V deep cycle battery with 5A 110V onboard charger</span></p><p><span>Lockable pump &amp; battery box</span></p><p><span>Ramps: 6.5 ft slide-in ramps with integrated ramp door</span></p><p><span>Gate: Rear combo gate (barn doors + spreader)</span></p><p><span>Sides: 24\" 10-gauge steel sides</span></p><p><span>Tie-Downs: (4) 1/2” D-rings inside the bed</span></p><p><span>Lighting: Recessed, grommet-mounted LED system</span></p><p><span>Wiring: Sealed modular cold-weather harness</span></p><p><span>Tires: ST235/80R16 Load Range E radial tires</span></p><p><span>Wheels: 6-lug bolt pattern</span></p><p><span>Spare Tire Mount: Side mount (spare sold separately)</span></p><p><span>Top Rail: 3\" x 2\" rectangular tubing top tail</span></p><p><span>Tarp System: Fully-formed tarp shroud with tarp &amp; rear tarp rod holders</span></p><p><span>Color: Black, professional paint with primer standard</span></p><p><span>Plug: 7-way RV connector</span></p><p><span>Stake Pockets: Along both sides</span></p><p><br></p><p><span>Why Choose the Big Tex 10LX?</span></p><p><span>This model combines strength, versatility, and premium construction—ideal for hauling gravel, debris, equipment, manure, and other materials. With its powerful hydraulic dump system and reinforced steel build, the 10LX is a reliable workhorse that performs day after day.</span></p><p><br></p><p><span>Available Now at Varner Equipment</span></p><p><span>Price: $8,560</span></p><p><span>Stock #100453</span></p>');
