INSERT INTO `wp_postmeta` VALUES ('1713','602','description','<h2><strong>Legend Trailer Mover</strong></h2><p>Features</p><p>Receiver plate mounts to most loader buckets without tools</p><p>Easily add accessories to receiver plate</p><p>Painted using a 2 part urethane process for an exceptional finish</p><p>Accessories are designed for use with our receiver plate only.</p><p>Lift Capacity: 1,000 lbs.</p><p>Lift limit is determined by receiver capacity or loader capacity, whichever is less.</p><p>Width : 45.75 inches</p><p>Height: 18 inches</p><p>Depth : 14 inches</p><p>Mounting Plate: 5/16 inch A-36 Steel</p><p>Gusset: ¼ inch A-36 Steel</p><p>Tube: 2-½ inch Seamless Tube -Accepts 2 inch Receiver Tube</p><p>Weight: 105 lbs.</p><p>Max Lift: 1000 lbs.</p><p>Stock #9527</p><p>PRICE: $450</p>');
