INSERT INTO `wp_postmeta` VALUES ('2159','706','description','<p>Brush Chief BR1205BL 5’ Standard-Duty Rotary Cutter – Reliable Cutting for Light Brush &amp; Grass </p><p><br></p><p>The Brush Chief 1200 Series Rotary Cutter is built tough for standard-duty mowing jobs around your property. Perfect for handling grass, weeds, and light brush up to 1.5” in diameter, this cutter combines durable construction with practical design to deliver consistent performance. </p><p><br></p><p>Key Features: </p><p><br></p><p>Cutting Capacity – Handles grass, weeds, and brush up to 1.5” in diameter. </p><p><br></p><p>Gearbox – Heavy-duty 55 HP gearbox for dependable power transfer. </p><p><br></p><p>Deck Construction – Durable 11-gauge deck built for long-lasting use. </p><p><br></p><p>Hitch Design – Flex hitch, CAT I Quick Hitch compatible for easy hookup. </p><p><br></p><p>Protection – Shear bolt PTO standard, with optional slip clutch available. </p><p><br></p><p>Blade System – Single spindle with two free-swinging blades helps reduce shock on impact with stationary objects. </p><p><br></p><p>Safety Shields – Equipped with driveline and clutch shields for operator protection. </p><p><br></p><p>Note – Front and rear safety chains not included. </p><p><br></p><p>Why Choose the Brush Chief 5’ Rotary Cutter? </p><p><br></p><p>This standard-duty cutter is ideal for acreage owners, hobby farmers, and light land maintenance. It’s tough enough to handle routine mowing jobs while staying easy to operate and maintain—offering excellent value for its size and class.</p>');
