INSERT INTO `wp_postmeta` VALUES ('2267','715','description','<p>Krone Big Pack 890 Large Square Baler – 3×3 Bale Size</p><p>Built for Efficiency</p><p>The Krone Big Pack 890 is a proven performer in large square baling, designed for maximum productivity and bale quality. With its 3×3 bale size and 1000 PTO drive, this baler delivers tight, uniform bales and is built to keep up with demanding operations.</p><p>Key Features:</p><p>Bale Size – Produces large square bales (3’ x 3’), ideal for handling and stacking.</p><p>PTO – 1000 PTO for efficient power transfer.</p><p>Tires – Main tires: 550/45-22.5 for field stability.</p><p>Sweep Tires – 16×6.50-8 NHS for smoother operation. Heavy-Duty Build – Krone engineering ensures durability, reliability, and consistent bale density.</p><p>Why Choose the Krone Big Pack 890?</p><p>This baler is built for operators who need high-capacity baling with consistent results. From hay to straw, the Big Pack 890 delivers dense, well-formed bales, reducing handling time and increasing transport efficiency. With Krone’s reputation for German engineering, you’re investing in equipment that works as hard as you do.</p>');
