INSERT INTO `wp_varner_inventory_ledger` VALUES ('38','598','create','1','varnerequipdev','V','created unit','{\"after\":{\"id\":598,\"title\":\"2026 Big Tex 10LX Dump Trailer\",\"year\":\"2026\",\"make\":\"Big Tex\",\"model\":\"10LX Dump Trailer\",\"stock_number\":\"100453\",\"vin\":\"16V1D1623T5454083\",\"price\":\"8560\",\"call_for_price\":false,\"condition\":\"New\",\"stock_status\":\"In Stock\",\"category\":\"Trailers\",\"color\":\"Black\",\"length\":\"12\",\"meter\":\"\",\"meter_type\":\"Hours\",\"intake_date\":\"\",\"description\":\"<h2><strong>Big Tex 10LX Dump Trailer \\u2013 Heavy-Duty, Hydraulic Lift, Fully Loaded with Features<\\/strong><\\/h2>\\n<p><span>Price: $8,560 | Stock #100453<\\/span><\\/p>\\n<p><\\/p>\\n<p><span>The Big Tex 10LX is a premium-grade dump trailer built for contractors, ranchers, landscapers, and anyone who needs dependable hauling power. With 10,000 lbs GVWR, a self-contained hydraulic lift, and reinforced steel construction, this trailer is engineered for serious work. Packed with professional-grade features, it offers superior durability, convenience, and hauling efficiency.<\\/span><\\/p>\\n<p><\\/p>\\n<p><span>Key Features:<\\/span><\\/p>\\n<p><span>Axles: (2) 5,200 lb premium cambered axles with quick-lubricating hubs<\\/span><\\/p>\\n<p><span>Brakes: Forward self-adjusting electric brakes<\\/span><\\/p>\\n<p><span>Suspension: Multi-leaf slipper spring with equalizer<\\/span><\\/p>\\n<p><span>Coupler: Adjustable forged 2-5\\/16&#8243; coupler<\\/span><\\/p>\\n<p><span>Safety Chains: 1\\/4&#8243; Grade 70 with safety latch hooks<\\/span><\\/p>\\n<p><span>Jack: 7,000 lb top-wind drop-leg jack<\\/span><\\/p>\\n<p><span>Frame: 6&#8243; channel frame<\\/span><\\/p>\\n<p><span>Crossmembers: 3&#8243; channel on 16&#8243; centers<\\/span><\\/p>\\n<p><span>Floor: 10-gauge smooth steel floor<\\/span><\\/p>\\n<p><span>Fenders: 9&#8243; x 72&#8243; diamond plate double square broke<\\/span><\\/p>\\n<p><span>Hydraulics:<\\/span><\\/p>\\n<p><span>Power up\\/power down &amp; gravity down hydraulic pump<\\/span><\\/p>\\n<p><span>Self-contained single cylinder lift<\\/span><\\/p>\\n<p><span>12V deep cycle battery with 5A 110V onboard charger<\\/span><\\/p>\\n<p><span>Lockable pump &amp; battery box<\\/span><\\/p>\\n<p><span>Ramps: 6.5 ft slide-in ramps with integrated ramp door<\\/span><\\/p>\\n<p><span>Gate: Rear combo gate (barn doors + spreader)<\\/span><\\/p>\\n<p><span>Sides: 24&#8243; 10-gauge steel sides<\\/span><\\/p>\\n<p><span>Tie-Downs: (4) 1\\/2\\u201d D-rings inside the bed<\\/span><\\/p>\\n<p><span>Lighting: Recessed, grommet-mounted LED system<\\/span><\\/p>\\n<p><span>Wiring: Sealed modular cold-weather harness<\\/span><\\/p>\\n<p><span>Tires: ST235\\/80R16 Load Range E radial tires<\\/span><\\/p>\\n<p><span>Wheels: 6-lug bolt pattern<\\/span><\\/p>\\n<p><span>Spare Tire Mount: Side mount (spare sold separately)<\\/span><\\/p>\\n<p><span>Top Rail: 3&#8243; x 2&#8243; rectangular tubing top tail<\\/span><\\/p>\\n<p><span>Tarp System: Fully-formed tarp shroud with tarp &amp; rear tarp rod holders<\\/span><\\/p>\\n<p><span>Color: Black, professional paint with primer standard<\\/span><\\/p>\\n<p><span>Plug: 7-way RV connector<\\/span><\\/p>\\n<p><span>Stake Pockets: Along both sides<\\/span><\\/p>\\n<p><\\/p>\\n<p><span>Why Choose the Big Tex 10LX?<\\/span><\\/p>\\n<p><span>This model combines strength, versatility, and premium construction\\u2014ideal for hauling gravel, debris, equipment, manure, and other materials. With its powerful hydraulic dump system and reinforced steel build, the 10LX is a reliable workhorse that performs day after day.<\\/span><\\/p>\\n<p><\\/p>\\n<p><span>Available Now at Varner Equipment<\\/span><\\/p>\\n<p><span>Price: $8,560<\\/span><\\/p>\\n<p><span>Stock #100453<\\/span><\\/p>\\n\",\"seller_info\":\"<p>Call or stop by to see it in person<\\/p>\\n<p>Varner Equipment<\\/p>\\n<p>1375 Hwy 50<\\/p>\\n<p>Delta, CO 81416<\\/p>\\n<p>(970) 874-0612<\\/p>\\n\",\"featured\":true,\"show_on_website\":true,\"images\":[\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/14LP-1.webp\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/14LP2-1.webp\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/14LP4-1.webp\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/14LP6-1.webp\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/14LP7-1.webp\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/14LP8-1.webp\"],\"image_ids\":[592,596,597,595,594,593],\"implements\":[],\"deleted_at\":\"\",\"last_action\":\"\",\"last_actor_name\":\"\",\"last_actor_initials\":\"\",\"last_action_at\":\"\"}}',NULL,'2026-05-04 21:53:17');
