INSERT INTO `wp_varner_inventory_ledger` VALUES ('55','687','update','2','Kel Majors','KM','make: Enorossi -> Krone; model: BATRAKE 8 -> Big Pack 890 Large Square Baler; stock_number: 11262 -> 100248','{\"diff\":{\"make\":{\"from\":\"Enorossi\",\"to\":\"Krone\"},\"model\":{\"from\":\"BATRAKE 8\",\"to\":\"Big Pack 890 Large Square Baler\"},\"stock_number\":{\"from\":\"11262\",\"to\":\"100248\"},\"vin\":{\"from\":\"202402854\",\"to\":\"WMKBP204S01173400\"},\"call_for_price\":{\"from\":false,\"to\":true},\"color\":{\"from\":\"Red\",\"to\":\"Green\\/Yellow\"},\"description\":{\"from\":\"<p>ERBR-8 <\\/p>\\n<p><\\/p>\\n<p>8 Wheel Bat Rake<\\/p>\\n<p><\\/p>\\n<p>Single Wheel Arm<\\/p>\\n<p><\\/p>\\n<p>60\\u2033 HD Wheels<\\/p>\\n<p><\\/p>\\n<p>7.5 Mil Teeth<\\/p>\\n<p><\\/p>\\n<p>HP20<\\/p>\\n<p><\\/p>\\n<p>Working Width 16.5\\u2032<\\/p>\\n\",\"to\":\"<p>Krone Big Pack 890 Large Square Baler \\u2013 3&#215;3 Bale Size<\\/p>\\n<p><\\/p>\\n<p>Built for Efficiency <\\/p>\\n<p><\\/p>\\n<p>The Krone Big Pack 890 is a proven performer in large square baling, designed for maximum productivity and bale quality. With its 3&#215;3 bale size and 1000 PTO drive, this baler delivers tight, uniform bales and is built to keep up with demanding operations. <\\/p>\\n<p><\\/p>\\n<p>Key Features: <\\/p>\\n<p><\\/p>\\n<p>Bale Size \\u2013 Produces large square bales (3\\u2019 x 3\\u2019), ideal for handling and stacking. <\\/p>\\n<p><\\/p>\\n<p>PTO \\u2013 1000 PTO for efficient power transfer. <\\/p>\\n<p><\\/p>\\n<p>Tires \\u2013 Main tires: 550\\/45-22.5 for field stability. <\\/p>\\n<p><\\/p>\\n<p>Sweep Tires \\u2013 16&#215;6.50-8 NHS for smoother operation. <\\/p>\\n<p><\\/p>\\n<p>Heavy-Duty Build \\u2013 Krone engineering ensures durability, reliability, and consistent bale density. <\\/p>\\n<p><\\/p>\\n<p>Why Choose the Krone Big Pack 890? <\\/p>\\n<p><\\/p>\\n<p>This baler is built for operators who need high-capacity baling with consistent results. From hay to straw, the Big Pack 890 delivers dense, well-formed bales, reducing handling time and increasing transport efficiency. With Krone\\u2019s reputation for German engineering, you\\u2019re investing in equipment that works as hard as you do.<\\/p>\\n\"},\"title\":{\"from\":\"2025 Enorossi BATRAKE 8\",\"to\":\"2025 Krone Big Pack 890 Large Square Baler\"}},\"before\":{\"id\":687,\"title\":\"2025 Enorossi BATRAKE 8\",\"year\":\"2025\",\"make\":\"Enorossi\",\"model\":\"BATRAKE 8\",\"stock_number\":\"11262\",\"vin\":\"202402854\",\"price\":\"8535\",\"call_for_price\":false,\"condition\":\"New\",\"stock_status\":\"In Stock\",\"category\":\"Hay Equipment\",\"color\":\"Red\",\"length\":\"16.5\\u2032\",\"meter\":\"\",\"meter_type\":\"Hours\",\"intake_date\":\"\",\"description\":\"<p>ERBR-8 <\\/p>\\n<p><\\/p>\\n<p>8 Wheel Bat Rake<\\/p>\\n<p><\\/p>\\n<p>Single Wheel Arm<\\/p>\\n<p><\\/p>\\n<p>60\\u2033 HD Wheels<\\/p>\\n<p><\\/p>\\n<p>7.5 Mil Teeth<\\/p>\\n<p><\\/p>\\n<p>HP20<\\/p>\\n<p><\\/p>\\n<p>Working Width 16.5\\u2032<\\/p>\\n\",\"seller_info\":\"<p>Call or stop by to see it in person<\\/p>\\n<p>Varner Equipment<\\/p>\\n<p>1375 Hwy 50<\\/p>\\n<p>Delta, CO 81416<\\/p>\\n<p>(970) 874-0612<\\/p>\\n\",\"featured\":false,\"show_on_website\":true,\"images\":[\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/1_Enrossi_8WheelBatRake.jpg\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/2_Enrossi_8WheelBatRake.jpg\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/3_Enrossi_8WheelBatRake.jpg\"],\"image_ids\":[690,689,688],\"implements\":[],\"deleted_at\":\"\",\"last_action\":\"update\",\"last_actor_name\":\"Kel Majors\",\"last_actor_initials\":\"KM\",\"last_action_at\":\"2026-05-11 16:36:45\"},\"after\":{\"id\":687,\"title\":\"2025 Krone Big Pack 890 Large Square Baler\",\"year\":\"2025\",\"make\":\"Krone\",\"model\":\"Big Pack 890 Large Square Baler\",\"stock_number\":\"100248\",\"vin\":\"WM