INSERT INTO `wp_varner_inventory_ledger` VALUES ('57','706','create','2','Kel Majors','KM','created unit','{\"after\":{\"id\":706,\"title\":\"2025 Brush Chief 1205\",\"year\":\"2025\",\"make\":\"Brush Chief\",\"model\":\"1205\",\"stock_number\":\"100282\",\"vin\":\"373488\",\"price\":\"2210\",\"call_for_price\":false,\"condition\":\"New\",\"stock_status\":\"In Stock\",\"category\":\"Hay Equipment\",\"color\":\"Black\",\"length\":\"5\'\",\"meter\":\"\",\"meter_type\":\"Hours\",\"intake_date\":\"\",\"description\":\"<p>Brush Chief BR1205BL 5\\u2019 Standard-Duty Rotary Cutter \\u2013 Reliable Cutting for Light Brush &amp; Grass <\\/p>\\n<p><\\/p>\\n<p>The Brush Chief 1200 Series Rotary Cutter is built tough for standard-duty mowing jobs around your property. Perfect for handling grass, weeds, and light brush up to 1.5\\u201d in diameter, this cutter combines durable construction with practical design to deliver consistent performance. <\\/p>\\n<p><\\/p>\\n<p>Key Features: <\\/p>\\n<p><\\/p>\\n<p>Cutting Capacity \\u2013 Handles grass, weeds, and brush up to 1.5\\u201d in diameter. <\\/p>\\n<p><\\/p>\\n<p>Gearbox \\u2013 Heavy-duty 55 HP gearbox for dependable power transfer. <\\/p>\\n<p><\\/p>\\n<p>Deck Construction \\u2013 Durable 11-gauge deck built for long-lasting use. <\\/p>\\n<p><\\/p>\\n<p>Hitch Design \\u2013 Flex hitch, CAT I Quick Hitch compatible for easy hookup. <\\/p>\\n<p><\\/p>\\n<p>Protection \\u2013 Shear bolt PTO standard, with optional slip clutch available. <\\/p>\\n<p><\\/p>\\n<p>Blade System \\u2013 Single spindle with two free-swinging blades helps reduce shock on impact with stationary objects. <\\/p>\\n<p><\\/p>\\n<p>Safety Shields \\u2013 Equipped with driveline and clutch shields for operator protection. <\\/p>\\n<p><\\/p>\\n<p>Note \\u2013 Front and rear safety chains not included. <\\/p>\\n<p><\\/p>\\n<p>Why Choose the Brush Chief 5\\u2019 Rotary Cutter? <\\/p>\\n<p><\\/p>\\n<p>This standard-duty cutter is ideal for acreage owners, hobby farmers, and light land maintenance. It\\u2019s tough enough to handle routine mowing jobs while staying easy to operate and maintain\\u2014offering excellent value for its size and class.<\\/p>\\n\",\"seller_info\":\"<p>Call or stop by to see it in person<\\/p>\\n<p>Varner Equipment<\\/p>\\n<p>1375 Hwy 50<\\/p>\\n<p>Delta, CO 81416<\\/p>\\n<p>(970) 874-0612<\\/p>\\n\",\"featured\":false,\"show_on_website\":true,\"images\":[\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/3_2025BrushChief1205_RotaryCutter-1.jpg\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/1_2025BrushChief1205_RotaryCutter-1.jpg\",\"https:\\/\\/varnerequipdev.wpenginepowered.com\\/wp-content\\/uploads\\/2026\\/05\\/2_2025BrushChief1205_RotaryCutter-1.jpg\"],\"image_ids\":[705,704,703],\"implements\":[],\"deleted_at\":\"\",\"last_action\":\"\",\"last_actor_name\":\"\",\"last_actor_initials\":\"\",\"last_action_at\":\"\"}}',NULL,'2026-05-11 17:27:57');
